// src/app/admin/keywords/page.tsx
'use client'

import { useCallback, useEffect, useMemo, useState } from 'react'
import { useAuthUser } from '@/app/providers'
import TranslationInput, { I18nValues } from '@/components/admin/TranslationInput'

type Keyword = {
  id: string
  keyword: string
  keyword_i18n?: any
  order: number
}

type ApiErr = {
  status: number
  code: string
  detail?: string
  raw?: string
}

type AdminGetOk = {
  ok: boolean
  data: Array<{ id: string; keyword: string; keyword_i18n: any; order: number | null | undefined }>
}

async function readError(res: Response): Promise<ApiErr> {
  const status = res.status
  const raw = await res.text().catch(() => '')
  let json: any = null
  try {
    json = raw ? JSON.parse(raw) : null
  } catch {
    json = null
  }

  const code =
    (json && typeof json.error === 'string' && json.error) ||
    res.statusText ||
    'unknown_error'

  const detail = json && typeof json.detail === 'string' ? json.detail : undefined
  const rawShort = raw ? raw.slice(0, 300) : ''

  return { status, code, detail, raw: rawShort }
}

function normalize(rows: AdminGetOk['data']): Keyword[] {
  const mapped = rows.map((r, idx) => ({
    id: String(r.id),
    keyword: String(r.keyword),
    keyword_i18n: r.keyword_i18n,
    order: Number.isFinite(Number(r.order)) ? Number(r.order) : idx,
  }))
  mapped.sort((a, b) => a.order - b.order)
  return mapped
}

export default function KeywordAdminPage() {
  const { user, loading } = useAuthUser() as any
  const authed = !!user

  const [keywords, setKeywords] = useState<Keyword[]>([])
  
  const [newKeyword, setNewKeyword] = useState('')
  const [newKeywordI18n, setNewKeywordI18n] = useState<I18nValues | null>(null)
  const [rawNewI18nData, setRawNewI18nData] = useState<{ keyword?: any }>({})

  const [loadingList, setLoadingList] = useState(false)
  const [busyId, setBusyId] = useState<string | null>(null)
  const [errorMsg, setErrorMsg] = useState<string | null>(null)

  // edit state
  const [editId, setEditId] = useState<string | null>(null)
  
  const [editKeyword, setEditKeyword] = useState('')
  const [editKeywordI18n, setEditKeywordI18n] = useState<I18nValues | null>(null)
  const [rawEditI18nData, setRawEditI18nData] = useState<{ keyword?: any }>({})
  
  const [editOrder, setEditOrder] = useState<string>('')

  const canInteract = authed && !loadingList && !busyId

  const fetchKeywords = useCallback(async () => {
    if (!authed) return

    setLoadingList(true)
    setErrorMsg(null)

    try {
      const res = await fetch('/api/keywords', {
        method: 'GET',
        cache: 'no-store',
      })

      if (!res.ok) {
        const err = await readError(res)
        setKeywords([])
        setErrorMsg(
          `?쒕쾭 API ?ㅻ쪟(GET): ${err.status} ${err.code}${err.detail ? ` (${err.detail})` : ''}${
            err.raw ? ` | raw: ${err.raw}` : ''
          }`
        )
        return
      }

      const json = (await res.json().catch(() => null)) as AdminGetOk | null
      const rows = json && Array.isArray((json as any).data) ? (json as any).data : []
      setKeywords(normalize(rows))
    } catch (e: any) {
      setKeywords([])
      setErrorMsg(`?ㅽ듃?뚰겕 ?ㅻ쪟(GET): ${e?.message ?? String(e)}`)
    } finally {
      setLoadingList(false)
    }
  }, [authed])

  useEffect(() => {
    if (!authed) return
    fetchKeywords()
  }, [authed, fetchKeywords])

  async function addKeyword() {
    if (!authed) return
    const value = newKeyword.trim()
    if (!value) return

    setLoadingList(true)
    setErrorMsg(null)

    const nextOrder = keywords.length > 0 ? Math.max(...keywords.map((k) => k.order)) + 1 : 0

    try {
      const res = await fetch('/api/keywords', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ keyword: value, keyword_i18n: newKeywordI18n, order: nextOrder }),
      })

      if (!res.ok) {
        const err = await readError(res)
        setErrorMsg(
          `?쒕쾭 API ?ㅻ쪟(ADD): ${err.status} ${err.code}${err.detail ? ` (${err.detail})` : ''}${
            err.raw ? ` | raw: ${err.raw}` : ''
          }`
        )
        return
      }

      setNewKeyword('')
      setNewKeywordI18n(null)
      setRawNewI18nData({})
      await fetchKeywords()
    } catch (e: any) {
      setErrorMsg(`?ㅽ듃?뚰겕 ?ㅻ쪟(ADD): ${e?.message ?? String(e)}`)
    } finally {
      setLoadingList(false)
    }
  }

  function startEdit(k: Keyword) {
    setEditId(k.id)
    setEditKeyword(k.keyword)
    setEditKeywordI18n(k.keyword_i18n ?? null)
    setRawEditI18nData({ keyword: k.keyword_i18n })
    setEditOrder(String(k.order))
    setErrorMsg(null)
  }

  function cancelEdit() {
    setEditId(null)
    setEditKeyword('')
    setEditKeywordI18n(null)
    setRawEditI18nData({})
    setEditOrder('')
  }

  async function saveEdit() {
    if (!authed || !editId) return

    const kw = editKeyword.trim()
    const ord = Number(editOrder)

    if (!kw) return setErrorMsg('?ㅼ썙??鍮꾩뼱?덉쓬.')
    if (Number.isNaN(ord)) return setErrorMsg('order ?レ옄?ъ빞 ??')

    setBusyId(editId)
    setErrorMsg(null)

    try {
      const res = await fetch('/api/keywords', {
        method: 'PUT',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ id: editId, keyword: editKeyword.trim(), keyword_i18n: editKeywordI18n, order: ord }),
      })

      if (!res.ok) {
        const err = await readError(res)
        setErrorMsg(
          `?쒕쾭 API ?ㅻ쪟(SAVE): ${err.status} ${err.code}${err.detail ? ` (${err.detail})` : ''}${
            err.raw ? ` | raw: ${err.raw}` : ''
          }`
        )
        return
      }

      cancelEdit()
      await fetchKeywords()
    } catch (e: any) {
      setErrorMsg(`?ㅽ듃?뚰겕 ?ㅻ쪟(UPDATE): ${e?.message ?? String(e)}`)
    } finally {
      setBusyId(null)
    }
  }

  async function deleteKeyword(id: string) {
    if (!authed) return

    setBusyId(id)
    setErrorMsg(null)

    try {
      const res = await fetch(`/api/keywords?id=${encodeURIComponent(id)}`, {
        method: 'DELETE',
      })

      if (!res.ok) {
        const err = await readError(res)
        setErrorMsg(
          `?쒕쾭 API ?ㅻ쪟(DEL): ${err.status} ${err.code}${err.detail ? ` (${err.detail})` : ''}${
            err.raw ? ` | raw: ${err.raw}` : ''
          }`
        )
        return
      }

      await fetchKeywords()
    } catch (e: any) {
      setErrorMsg(`?ㅽ듃?뚰겕 ?ㅻ쪟(DEL): ${e?.message ?? String(e)}`)
    } finally {
      setBusyId(null)
    }
  }

  if (loading) {
    return (
      <main className="min-h-screen bg-[#333333] text-[#eae3de]">
        <div className="max-w-3xl mx-auto px-4 py-12">
          <h1 className="text-2xl font-bold">Popular Keywords (Admin)</h1>
          <div className="mt-4 p-4 rounded bg-[#2b2b2b] text-gray-200">Checking login??/div>
        </div>
      </main>
    )
  }

  if (!authed) {
    return (
      <main className="min-h-screen bg-[#333333] text-[#eae3de]">
        <div className="max-w-3xl mx-auto px-4 py-12">
          <h1 className="text-2xl font-bold">Popular Keywords (Admin)</h1>
          <p className="mt-2 text-sm text-gray-300">
            ?댁젣 Admin UUID 濡쒓렇??諛⑹떇 ?쒓굅?덇퀬, <b>濡쒓렇?몃맂 怨꾩젙</b> + <b>?덉슜???대찓??/b>留??묎렐 媛??
          </p>
          <div className="mt-4 p-4 rounded bg-[#2b2b2b] text-gray-200">
            癒쇱? ?곷떒 硫붾돱?먯꽌 濡쒓렇????
          </div>
        </div>
      </main>
    )
  }

  return (
    <main className="min-h-screen bg-[#333333] text-[#eae3de]">
      <div className="max-w-3xl mx-auto px-4 py-12">
        <div className="flex items-center justify-between gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold mb-1">Popular Keywords (Admin)</h1>
            <p className="text-xs text-gray-400">
              Logged in as <span className="text-gray-200">{user?.email ?? user?.id ?? 'unknown'}</span>
            </p>
          </div>
        </div>

        <form
          onSubmit={(e) => {
            e.preventDefault()
            addKeyword()
          }}
          className="mt-4"
        >
          <TranslationInput
            label="New Keyword (English)"
            baseString={newKeyword}
            i18nData={rawNewI18nData.keyword}
            disabled={!canInteract || loadingList}
            onChange={(en, localized) => {
              setNewKeyword(en)
              setNewKeywordI18n(localized)
            }}
          />
          <button
            type="submit"
            disabled={!canInteract || !newKeyword.trim() || loadingList}
            className="w-full mt-2 rounded bg-[#3EB6F1] px-4 py-2 font-semibold text-black hover:opacity-90 disabled:opacity-50"
          >
            + Add
          </button>
        </form>

        <div className="flex items-center gap-2 mb-4">
          <button
            onClick={fetchKeywords}
            disabled={loadingList || !!busyId}
            className="px-3 py-1 bg-[#555] text-white rounded hover:opacity-90 text-sm disabled:opacity-60"
          >
            Refresh
          </button>
          <span className="text-xs text-gray-400">紐⑸줉 濡쒕뵫? GET /api/keywords (濡쒓렇???덉슜?대찓???꾩슂)</span>
        </div>

        {errorMsg && <div className="mb-4 text-sm text-red-300 whitespace-pre-wrap">{errorMsg}</div>}

        <div className="rounded-2xl border border-gray-700 bg-[#3a3a3a]">
          {keywords.length === 0 ? (
            <div className="p-4 text-sm text-gray-300">{loadingList ? 'Loading?? : 'No keywords yet.'}</div>
          ) : (
            <ul className="divide-y divide-gray-700">
              {keywords.map((k) => {
                const isEditing = editId === k.id
                return (
                  <li key={k.id} className="p-3 flex items-center gap-3">
                    <span className="w-14 text-sm text-gray-300">#{k.order}</span>

                    {isEditing ? (
                      // EDIT MODE
                      <div className="flex flex-col gap-3">
                        <TranslationInput
                          label="Edit Keyword"
                          baseString={editKeyword}
                          i18nData={rawEditI18nData.keyword}
                          disabled={!canInteract || loadingList}
                          onChange={(en, localized) => {
                            setEditKeyword(en)
                            setEditKeywordI18n(localized)
                          }}
                        />

                        <div className="flex items-center gap-2">
                          <label className="text-sm font-semibold text-white/70 w-24">Order Index</label>
                          <input
                            type="number"
                            value={editOrder}
                            onChange={(e) => setEditOrder(e.target.value)}
                            className="w-24 rounded bg-white/10 px-3 py-2 text-white focus:outline-none"
                            placeholder="Order"
                          />
                        </div>

                        <div className="flex gap-2">
                          <button
                            onClick={saveEdit}
                            disabled={!canInteract || loadingList}
                            className="rounded bg-[#3EB6F1] px-4 py-1.5 text-sm font-semibold text-black hover:opacity-90 disabled:opacity-50"
                          >
                            Save
                          </button>
                          <button
                            onClick={cancelEdit}
                            disabled={!canInteract || loadingList}
                            className="rounded bg-white/10 px-4 py-1.5 text-sm hover:bg-white/20 disabled:opacity-50"
                          >
                            Cancel
                          </button>
                        </div>
                      </div>
                    ) : (
                      <>
                        <span className="flex-1 break-words">{k.keyword}</span>
                        <button
                          onClick={() => startEdit(k)}
                          disabled={loadingList || !!busyId}
                          className="px-3 py-1 bg-[#666] text-white rounded hover:opacity-90 text-sm disabled:opacity-60"
                        >
                          Edit
                        </button>
                        <button
                          onClick={() => deleteKeyword(k.id)}
                          disabled={busyId === k.id || loadingList}
                          className="px-3 py-1 bg-[#8a1a1d] text-white rounded hover:opacity-90 text-sm disabled:opacity-50"
                        >
                          {busyId === k.id ? 'Deleting?? : 'Delete'}
                        </button>
                      </>
                    )}
                  </li>
                )
              })}
            </ul>
          )}
        </div>
      </div>
    </main>
  )
}

// src/app/admin/kyk-keywords/page.tsx
'use client'

import { useCallback, useEffect, useState } from 'react'
import { useAuthUser } from '@/app/providers'

type KykAdminKeywordRow = {
  mbti_type: string
  keywords: string[]
  updated_at: string
}

type ApiGetOk = {
  ok: boolean
  data: KykAdminKeywordRow[]
}

const ALL_MBTI_TYPES = [
  'intj', 'intp', 'entj', 'entp',
  'infj', 'infp', 'enfj', 'enfp',
  'istj', 'istp', 'estj', 'estp',
  'isfj', 'isfp', 'esfj', 'esfp',
]

export default function KykKeywordAdminPage() {
  const { user, loading } = useAuthUser() as any
  const authed = !!user

  const [rows, setRows] = useState<Record<string, string[]>>({})
  const [loadingList, setLoadingList] = useState(false)
  const [busyId, setBusyId] = useState<string | null>(null)
  const [errorMsg, setErrorMsg] = useState<string | null>(null)
  const [successMsg, setSuccessMsg] = useState<string | null>(null)

  const fetchKeywords = useCallback(async () => {
    if (!authed) return

    setLoadingList(true)
    setErrorMsg(null)
    setSuccessMsg(null)

    try {
      const res = await fetch('/api/kyk-keywords', {
        method: 'GET',
        cache: 'no-store',
      })

      if (!res.ok) {
        setErrorMsg(`API Error (GET): ${res.status}`)
        return
      }

      const json = (await res.json().catch(() => null)) as ApiGetOk | null
      const fetchedData = json?.data || []

      const newRows: Record<string, string[]> = {}

      // Initialize with default empty slots to prevent undefined
      ALL_MBTI_TYPES.forEach(mbti => {
        newRows[mbti] = ['', '', '']
      })

      // Override with DB data
      fetchedData.forEach(row => {
        const paddedKeywords = [...(row.keywords || [])]
        while (paddedKeywords.length < 3) paddedKeywords.push('')
        newRows[row.mbti_type] = paddedKeywords.slice(0, 3)
      })

      setRows(newRows)
    } catch (e: any) {
      setErrorMsg(`Network Error: ${e?.message ?? String(e)}`)
    } finally {
      setLoadingList(false)
    }
  }, [authed])

  useEffect(() => {
    if (!authed) return
    fetchKeywords()
  }, [authed, fetchKeywords])

  const handleKeywordChange = (mbti: string, index: number, value: string) => {
    setRows(prev => {
      const currentArr = [...(prev[mbti] || ['', '', ''])]
      currentArr[index] = value
      return { ...prev, [mbti]: currentArr }
    })
  }

  const saveMbtiKeywords = async (mbti: string) => {
    if (!authed) return

    setBusyId(mbti)
    setErrorMsg(null)
    setSuccessMsg(null)

    const keywordsToSave = (rows[mbti] || []).map(k => k.trim()).filter(Boolean)

    try {
      const res = await fetch('/api/kyk-keywords', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ mbti_type: mbti, keywords: keywordsToSave }),
      })

      if (!res.ok) {
        setErrorMsg(`Update Failed (${mbti}): ${res.status}`)
        return
      }

      setSuccessMsg(`Successfully updated keywords for ${mbti.toUpperCase()}`)
      await fetchKeywords()
    } catch (e: any) {
      setErrorMsg(`Network Error: ${e?.message ?? String(e)}`)
    } finally {
      setBusyId(null)
      setTimeout(() => setSuccessMsg(null), 3000)
    }
  }

  if (loading) {
    return (
      <main className="min-h-screen bg-[#333333] text-[#eae3de]">
        <div className="max-w-4xl mx-auto px-4 py-12">
          <h1 className="text-2xl font-bold">KYK Keywords (Admin)</h1>
          <div className="mt-4 p-4 rounded bg-[#2b2b2b] text-gray-200">Checking login??/div>
        </div>
      </main>
    )
  }

  if (!authed) {
    return (
      <main className="min-h-screen bg-[#333333] text-[#eae3de]">
        <div className="max-w-4xl mx-auto px-4 py-12">
          <h1 className="text-2xl font-bold">KYK Keywords (Admin)</h1>
          <div className="mt-4 p-4 rounded bg-[#2b2b2b] text-gray-200">
            You must be logged in with an admin email to access this page.
          </div>
        </div>
      </main>
    )
  }

  return (
    <main className="min-h-screen bg-[#333333] text-[#eae3de]">
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="flex items-center justify-between gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold mb-1">KYK Dynamic Result Keywords (Admin)</h1>
            <p className="text-sm text-gray-400">
              Set the 3 keywords (Translation Keys or Raw Text) that appear inside the KYK result card for each MBTI type.
            </p>
          </div>
          <button
            onClick={fetchKeywords}
            disabled={loadingList || !!busyId}
            className="px-4 py-2 bg-[#555] text-white rounded hover:opacity-90 text-sm disabled:opacity-60"
          >
            Refresh Data
          </button>
        </div>

        {errorMsg && <div className="mb-4 p-3 bg-red-900/50 border border-red-700 rounded text-sm text-red-100">{errorMsg}</div>}
        {successMsg && <div className="mb-4 p-3 bg-green-900/50 border border-green-700 rounded text-sm text-green-100">{successMsg}</div>}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-4">
          {ALL_MBTI_TYPES.map((mbti) => {
            const currentKeywords = rows[mbti] || ['', '', '']
            const isSaving = busyId === mbti

            return (
              <div key={mbti} className="flex flex-col bg-[#3a3a3a] border border-gray-700 rounded-lg p-4">
                <div className="flex justify-between items-center mb-3">
                  <h2 className="text-lg font-bold text-[#3EB6F1]">{mbti.toUpperCase()}</h2>
                  <button
                    onClick={() => saveMbtiKeywords(mbti)}
                    disabled={isSaving || loadingList}
                    className="px-3 py-1 bg-[#3EB6F1] text-black text-sm font-semibold rounded hover:opacity-90 disabled:opacity-50"
                  >
                    {isSaving ? 'Saving...' : 'Save'}
                  </button>
                </div>

                <div className="space-y-2">
                  {[0, 1, 2].map(idx => (
                    <div key={idx} className="flex items-center gap-2">
                      <span className="text-xs text-gray-400 w-4">{idx + 1}.</span>
                      <input
                        type="text"
                        value={currentKeywords[idx]}
                        onChange={(e) => handleKeywordChange(mbti, idx, e.target.value)}
                        placeholder="e.g keyword_learning_routine"
                        className="flex-1 rounded border border-gray-600 bg-[#2b2b2b] p-2 text-sm text-[#eae3de] placeholder-gray-500 focus:outline-none focus:border-[#3EB6F1]"
                      />
                    </div>
                  ))}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </main>
  )
}

import type { Metadata } from 'next'
import { cookies } from 'next/headers'
import { createServerClient } from '@supabase/ssr'
import { redirect } from 'next/navigation'
import type { Database } from '@/lib/database.types'
import { requireAdminAuth } from '@/lib/auth/isAdmin'
import AdminSidebar from '@/components/admin/AdminSidebar'

export const metadata: Metadata = {
  title: 'AI ?≪븘肄붿튂 - Admin',
  description: '愿由ъ옄 ?섏씠吏',
}

export default async function AdminLayout({
  children,
}: Readonly<{ children: React.ReactNode }>) {
  const auth = await requireAdminAuth()

  if (!auth.ok) {
    if (auth.status === 401) {
      redirect('/')
    }
    return (
      <main className="min-h-screen bg-[#333333] text-[#eae3de] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-[#222222] border border-red-900 rounded-lg p-8 text-center shadow-xl">
          <h1 className="text-3xl font-bold text-red-500 mb-4">403 Forbidden</h1>
          <p className="text-gray-300">{auth.detail}</p>
        </div>
      </main>
    )
  }

  const user = auth.user

  return (
    <div className="flex min-h-screen bg-[#333333] text-[#eae3de] font-sans">
      <AdminSidebar userEmail={user.email} />
      <div className="flex-1 overflow-x-hidden">
        {children}
      </div>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useRef, useState } from 'react'
import { useAuthUser, useSupabase } from '@/app/providers'
import type { Tables } from '@/lib/database.types'
import TranslationInput, { I18nValues } from '@/components/admin/TranslationInput'

type NewsPost = Tables<'news_posts'>

const NEWS_IMAGE_BUCKET = 'news-images'

function yyyymmddhhmmss(d = new Date()) {
  const pad = (n: number) => String(n).padStart(2, '0')
  return (
    d.getFullYear() +
    pad(d.getMonth() + 1) +
    pad(d.getDate()) +
    pad(d.getHours()) +
    pad(d.getMinutes()) +
    pad(d.getSeconds())
  )
}

function slugify(input: string) {
  const base = input
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[^\w\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
  return base || `news-${yyyymmddhhmmss()}`
}

function extFromFileName(name: string) {
  const m = name.toLowerCase().match(/\.([a-z0-9]+)$/)
  return m?.[1] || 'jpg'
}

export default function AdminNewsPage() {
  const supabase = useSupabase()
  const { user, loading } = useAuthUser() as any

  const authed = !!user

  const fileInputRef = useRef<HTMLInputElement | null>(null)

  const [newsList, setNewsList] = useState<NewsPost[]>([])

  const [editingId, setEditingId] = useState<string | null>(null)
  const [title, setTitle] = useState('')
  const [titleI18n, setTitleI18n] = useState<I18nValues | null>(null)
  
  const [content, setContent] = useState('')
  const [contentI18n, setContentI18n] = useState<I18nValues | null>(null)

  const [rawI18nData, setRawI18nData] = useState<{ title?: any; content?: any }>({})

  const [slug, setSlug] = useState('')
  const [slugTouched, setSlugTouched] = useState(false)
  const [showAdvanced, setShowAdvanced] = useState(false)

  // ??DB????λ맆 cover_image_url (public URL ???
  const [coverUrl, setCoverUrl] = useState<string | null>(null)

  // ???덈줈 ?좏깮???뚯씪(?낅줈?쒕뒗 Save/Create ??
  const [coverFile, setCoverFile] = useState<File | null>(null)

  // ???붾㈃ ?꾨━酉?濡쒖뺄 objectURL ?먮뒗 coverUrl)
  const [coverPreviewUrl, setCoverPreviewUrl] = useState<string | null>(null)
  const [coverObjectUrl, setCoverObjectUrl] = useState<string | null>(null)

  const [saving, setSaving] = useState(false)
  const [err, setErr] = useState('')

  const autoSlug = useMemo(() => slugify(title), [title])

  useEffect(() => {
    if (!slugTouched) setSlug(autoSlug)
  }, [autoSlug, slugTouched])

  const fetchNews = async () => {
    // ??DB???녿뒗 detail_markdown ?덈? select?섏? 留?寃?r
    const { data, error } = await supabase
      .from('news_posts')
      .select('id, title, slug, content, created_at, user_id, cover_image_url, category, title_i18n, content_i18n')
      .order('created_at', { ascending: false })

    if (error) {
      console.error(error)
      setErr(error.message)
      return
    }
    setNewsList((data as any) ?? [])
  }

  useEffect(() => {
    fetchNews()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const revokeObjectUrlIfAny = () => {
    if (coverObjectUrl) {
      try {
        URL.revokeObjectURL(coverObjectUrl)
      } catch {}
