  const onPickCoverFile = (file: File | null) => {
    revokeObjectUrlIfAny()
    setCoverFile(file)

    if (!file) {
      setCoverPreviewUrl(coverUrl)
      return
    }
    const url = URL.createObjectURL(file)
    setCoverObjectUrl(url)
    setCoverPreviewUrl(url)
  }

  const openFilePicker = () => {
    if (!authed) {
      setErr('You must be logged in to upload images.')
      return
    }
    fileInputRef.current?.click()
  }

  const canInteract = authed && !saving

  if (loading) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <h1 className="text-2xl font-bold mb-3">?썱截?News Admin</h1>
        <div className="p-4 rounded bg-gray-800 text-gray-200">Checking login??/div>
      </div>
    )
  }

  if (!authed) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <h1 className="text-2xl font-bold mb-3">?썱截?News Admin</h1>
        <div className="p-4 rounded bg-gray-800 text-gray-200">濡쒓렇?명빐???댁뒪 ?묒꽦/?섏젙/??젣 媛?ν븿.</div>
      </div>
    )
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <h1 className="text-2xl font-bold mb-6">?썱截?News Admin</h1>

      <div className="mb-8">
        <h2 className="text-xl font-semibold mb-2">{editingId ? 'Edit News' : 'Create News'}</h2>

        <TranslationInput
          label="News Title"
          baseString={title}
          i18nData={rawI18nData.title}
          disabled={!canInteract}
          onChange={(en, localized) => {
            setTitle(en)
            setTitleI18n(localized)
          }}
        />

        <TranslationInput
          label="News Content (Markdown or plain text)"
          baseString={content}
          i18nData={rawI18nData.content}
          isTextArea
          disabled={!canInteract}
          maxLengthHint="Long markdown may take time to auto-translate and require link formatting checks."
          onChange={(en, localized) => {
            setContent(en)
            setContentI18n(localized)
          }}
        />

        <div className="mb-4">
          <div className="text-sm text-gray-300 mb-2">Thumbnail (cover image)</div>

          <div className="flex items-start gap-4">
            <div className="w-[140px] h-[140px] bg-gray-700 rounded overflow-hidden shrink-0 flex items-center justify-center">
              {coverPreviewUrl ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img src={coverPreviewUrl} alt="cover preview" className="w-full h-full object-cover" />
              ) : (
                <div className="text-xs text-gray-300">No image</div>
              )}
            </div>

            <div className="flex-1">
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={(e) => onPickCoverFile(e.target.files?.[0] ?? null)}
                className="hidden"
                disabled={!canInteract}
              />

              <div className="flex items-center gap-2">
                <button
                  type="button"
                  onClick={openFilePicker}
                  disabled={!canInteract}
                  className="px-3 py-2 bg-gray-700 text-white rounded hover:opacity-80 disabled:opacity-60 text-sm"
                >
                  {coverFile ? 'Change image' : 'Select image'}
                </button>

                <div className="text-xs text-gray-300 truncate">
                  {coverFile ? coverFile.name : coverUrl ? 'Using saved image' : 'No file selected'}
                </div>
              </div>

              <div className="mt-2 text-xs text-gray-400">
                ?낅줈?쒕뒗 <b>Create/Save</b> 踰꾪듉???꾨? ??DB????λ맖.
              </div>

              <div className="mt-3 flex gap-2">
                <button
                  type="button"
                  onClick={clearCoverSelection}
                  disabled={!canInteract}
                  className="px-3 py-2 bg-gray-700 text-white rounded hover:opacity-80 disabled:opacity-60 text-sm"
                >
                  Clear file selection
                </button>

                <button
                  type="button"
                  onClick={removeCover}
                  disabled={!canInteract}
                  className="px-3 py-2 bg-gray-600 text-white rounded hover:opacity-80 disabled:opacity-60 text-sm"
                >
                  Remove cover (set empty)
                </button>
              </div>

              {(coverUrl || coverFile) && (
                <div className="mt-3 text-xs text-gray-400 break-all">
                  <div>Saved cover_image_url: {coverUrl || '(none)'}</div>
                  <div>Selected file: {coverFile ? coverFile.name : '(none)'}</div>
                </div>
              )}
            </div>
          </div>
        </div>

        <details
          className="mb-3"
          open={showAdvanced}
          onToggle={(e) => setShowAdvanced((e.target as HTMLDetailsElement).open)}
        >
          <summary className="cursor-pointer text-sm text-gray-300">Advanced options (edit slug)</summary>
          <div className="mt-2">
            <input
              placeholder={`Auto: ${autoSlug}`}
              value={slug}
              onChange={(e) => {
                setSlugTouched(true)
                setSlug(e.target.value)
              }}
              disabled={!canInteract}
              className="w-full p-2 bg-gray-800 text-white rounded disabled:opacity-60"
            />
            <p className="mt-1 text-xs text-gray-400">Leave empty to auto-generate from the title.</p>
          </div>
        </details>

        {err && <p className="mb-3 text-sm text-red-300">{err}</p>}

        <div className="flex gap-2">
          <button
            onClick={handleSubmit}
            disabled={!canInteract}
            className="px-4 py-2 bg-[#9F1D23] text-white rounded hover:opacity-80 disabled:opacity-60"
          >
            {saving ? (editingId ? 'Saving?? : 'Creating??) : editingId ? 'Save' : 'Create'}
          </button>

          {editingId && (
            <button
              onClick={clearForm}
              disabled={!canInteract}
              className="px-4 py-2 bg-gray-600 text-white rounded hover:opacity-80 disabled:opacity-60"
            >
              Cancel
            </button>
          )}
        </div>
      </div>

      <div>
        <h2 className="text-xl font-semibold mb-3">News List</h2>
        <ul className="space-y-2">
          {newsList.map((post) => {
            const cu = (post as any).cover_image_url as string | null
            return (
              <li key={post.id} className="border-b border-gray-600 pb-2">
                <div className="flex gap-3 items-center">
                  <div className="w-10 h-10 bg-gray-700 rounded overflow-hidden shrink-0 flex items-center justify-center">
                    {cu ? (
                      // eslint-disable-next-line @next/next/no-img-element
                      <img src={cu} alt="thumb" className="w-full h-full object-cover" />
                    ) : (
                      <span className="text-[10px] text-gray-300">No</span>
                    )}
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className="truncate">
                      <span className="text-lg font-medium">{post.title}</span>{' '}
                      <span className="text-sm text-gray-400">/news/{post.slug}</span>
                    </div>
                    <p className="text-xs text-gray-400">
                      {post.created_at ? new Date(post.created_at).toLocaleString('en-US') : ''}
                    </p>
                  </div>

                  <div className="flex gap-3 text-sm shrink-0">
                    <button
                      onClick={() => handleEdit(post)}
                      disabled={!canInteract}
                      className="text-blue-400 hover:underline disabled:opacity-60"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDelete(post.id)}
                      disabled={!canInteract}
                      className="text-red-400 hover:underline disabled:opacity-60"
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </li>
            )
          })}

          {newsList.length === 0 && <li className="text-sm text-gray-400">No posts yet.</li>}
        </ul>
      </div>
    </div>
  )
}

'use server'

import { redirect } from 'next/navigation'
import { requireAdmin } from '@/lib/adminguard'

export async function createTeamItemAction(formData: FormData) {
  const { ok, supabase } = await requireAdmin()
  if (!ok) redirect('/')

  const sb = supabase

  const title = String(formData.get('title') ?? '').trim()
  const slug = String(formData.get('slug') ?? '').trim()
  if (!title || !slug) throw new Error('title/slug required')

  const titleI18nRaw = String(formData.get('title_i18n') ?? '')
  const title_i18n = titleI18nRaw !== 'null' ? JSON.parse(titleI18nRaw) : null

  const descI18nRaw = String(formData.get('description_i18n') ?? '')
  const description_i18n = descI18nRaw !== 'null' ? JSON.parse(descI18nRaw) : null

  const detailI18nRaw = String(formData.get('detail_markdown_i18n') ?? '')
  const detail_markdown_i18n = detailI18nRaw !== 'null' ? JSON.parse(detailI18nRaw) : null

  const description = String(formData.get('description') ?? '').trim() || null
  const cover_image_url = String(formData.get('cover_image_url') ?? '').trim() || null
  const detail_markdown = String(formData.get('detail_markdown') ?? '').trim() || null

  const tags = String(formData.get('tags') ?? '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)

  const gallery_urls = String(formData.get('gallery_urls') ?? '')
    .split('\n')
    .map((s) => s.trim())
    .filter(Boolean)

  // Use 'any' to bypass TS strict linting during the migration phase before `_i18n` columns are typed in Database
  const payload: any = {
    title,
    title_i18n,
    slug,
    description,
    description_i18n,
    cover_image_url,
    detail_markdown,
    detail_markdown_i18n,
    tags: tags.length ? tags : null,
    gallery_urls: gallery_urls.length ? gallery_urls : null,

    base_price: Number(formData.get('base_price') ?? 10000),
    min_price: Number(formData.get('min_price') ?? 7000),
    discount_step_percent: Number(formData.get('discount_step_percent') ?? 1),
    discount_step_every: Number(formData.get('discount_step_every') ?? 10),
    max_discount_percent: Number(formData.get('max_discount_percent') ?? 30),
    is_active: formData.get('is_active') === 'on',
  }

  const { data, error } = await sb
    .from('team_items')
    .insert([payload])
    .select('id')
    .single()

  if (error) throw new Error(error.message)

  // Fix the typo "team-itemss" that existed in the codebase
  redirect(`/admin/team-items/${data.id}`)
}

// src/app/admin/team/[teamId]/activities/ActivitiesClient.tsx
'use client'

import { useMemo, useState } from 'react'
import { useSupabase } from '@/app/providers'
import type { Tables } from '@/lib/database.types'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'

type ActivityRow = Tables<'team_activities'>

const BUCKET = 'team-images'

function safeFileExt(name: string) {
  const parts = name.split('.')
  return parts.length > 1 ? parts.pop()!.toLowerCase() : 'png'
}

function ymd(d: string | null) {
  if (!d) return ''
  try {
    return new Date(d).toLocaleDateString('en-US')
  } catch {
    return ''
  }
}

function mdText(v: unknown) {
  return String(v ?? '').trim()
}

export default function ActivitiesClient({
  teamId,
  initial,
}: {
  teamId: string
  initial: ActivityRow[]
}) {
  const supabase = useSupabase()

  const [list, setList] = useState<ActivityRow[]>(initial ?? [])
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [err, setErr] = useState('')

  // ???앹꽦/?섏젙 怨듭슜)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [title, setTitle] = useState('')
  const [body, setBody] = useState('')
  const [isActive, setIsActive] = useState(true)
  const [sortOrder, setSortOrder] = useState<number>(0)
  const [startsAt, setStartsAt] = useState<string>('')
  const [endsAt, setEndsAt] = useState<string>('')

  const [imageUrl, setImageUrl] = useState<string>('')
  const [imageFile, setImageFile] = useState<File | null>(null)

  const resetForm = () => {
    setEditingId(null)
    setTitle('')
    setBody('')
    setIsActive(true)
    setSortOrder(0)
    setStartsAt('')
    setEndsAt('')
    setImageUrl('')
    setImageFile(null)
    setErr('')
  }

  const openCreate = () => {
    resetForm()
  }

  const openEdit = (a: ActivityRow) => {
    setEditingId(a.id)
    setTitle(a.title ?? '')
    const b = ((a as any).body ?? a.description ?? '') as string
    setBody(b)
    setIsActive(Boolean((a as any).is_active ?? true))
    setSortOrder(Number((a as any).sort_order ?? 0))
    setStartsAt((a.starts_at ?? '') as any)
    setEndsAt((a.ends_at ?? '') as any)
    setImageUrl(((a as any).image_url ?? '') as string)
    setImageFile(null)
    setErr('')
  }

  const previewUrl = useMemo(() => {
    if (imageFile) return URL.createObjectURL(imageFile)
    return imageUrl || ''
  }, [imageFile, imageUrl])

  const uploadImageIfNeeded = async (): Promise<string | null> => {
    if (!imageFile) return imageUrl ? imageUrl : null

    setUploading(true)
    setErr('')

    const ext = safeFileExt(imageFile.name)
    const path = `team-activities/${teamId}/${Date.now()}.${ext}`

    const { error: upErr } = await supabase.storage.from(BUCKET).upload(path, imageFile, {
      cacheControl: '3600',
      upsert: false,
      contentType: imageFile.type || undefined,
    })

    if (upErr) {
      setUploading(false)
      setErr('Upload failed: ' + upErr.message)
      return null
    }

    const { data } = supabase.storage.from(BUCKET).getPublicUrl(path)
    const publicUrl = data?.publicUrl ?? null

    setUploading(false)
    return publicUrl
  }

  const refetch = async () => {
    const { data, error } = await supabase
      .from('team_activities')
      .select('id, team_id, title, body, description, image_url, is_active, sort_order, starts_at, ends_at, created_at')
      .eq('team_id', teamId)
      .order('sort_order', { ascending: true })
      .order('created_at', { ascending: false })

    if (error) {
      setErr(error.message)
      return
    }
    setList((data ?? []) as ActivityRow[])
  }

  const save = async () => {
    const t = title.trim()
    if (!t) {
      setErr('Title is required.')
      return
    }

    setSaving(true)
    setErr('')

    const finalImageUrl = await uploadImageIfNeeded()
    if (imageFile && !finalImageUrl) {
      setSaving(false)
      return
    }

    const payload: any = {
      team_id: teamId,
      title: t,
      body: body.trim() ? body.trim() : null,
      description: body.trim() ? body.trim() : null,
      image_url: finalImageUrl ? finalImageUrl : null,
      is_active: Boolean(isActive),
      sort_order: Number.isFinite(sortOrder) ? sortOrder : 0,
      starts_at: startsAt ? startsAt : null,
      ends_at: endsAt ? endsAt : null,
    }

    try {
      if (editingId) {
        const { error } = await supabase.from('team_activities').update(payload).eq('id', editingId)
        if (error) {
          setErr('Update failed: ' + error.message)
          return
        }
      } else {
        const { error } = await supabase.from('team_activities').insert([payload])
        if (error) {
          setErr('Create failed: ' + error.message)
          return
        }
      }

      resetForm()
      await refetch()
    } finally {
      setSaving(false)
    }
  }

  const remove = async (id: string) => {
    const ok = confirm('Delete this activity?')
    if (!ok) return

    const { error } = await supabase.from('team_activities').delete().eq('id', id)
    if (error) {
      setErr('Delete failed: ' + error.message)
      return
    }
    if (editingId === id) resetForm()
    refetch()
  }

  const bumpSort = async (id: string, delta: number) => {
    const row = list.find((x) => x.id === id)
    if (!row) return
    const cur = Number((row as any).sort_order ?? 0)
    const next = cur + delta

    const { error } = await supabase.from('team_activities').update({ sort_order: next } as any).eq('id', id)
    if (error) {
      setErr('Sort update failed: ' + error.message)
      return
    }
    refetch()
  }

  return (
    <div className="grid grid-cols-1 gap-8 md:grid-cols-2">
      {/* LEFT: 由ъ뒪??*/}
      <div>
        <div className="flex items-center justify-between">
          <h2 className="text-[18px] font-semibold">Activities</h2>
          <button onClick={openCreate} className="rounded-lg bg-[#1e1e1e] px-4 py-2 text-[13px] font-semibold text-white">
            + New
          </button>
        </div>

        <p className="mt-2 text-[13px] font-medium text-[#b4b4b4]">
          ?뺣젹? sort_order ?ㅻ쫫李⑥닚. is_active=false??? ?곸꽭 ?섏씠吏?먯꽌 ?④?.
        </p>

        {err && <div className="mt-3 rounded-lg border border-red-200 bg-red-50 p-3 text-[13px] text-red-700">{err}</div>}

        <div className="mt-6 space-y-3">
