            className="mt-2 h-[56px] w-full rounded-xl bg-[#1e1e1e] text-[15px] font-semibold text-white disabled:opacity-60"
          >
            {uploading ? 'Uploading?? : saving ? 'Saving?? : editingId ? 'Save changes' : 'Create'}
          </button>
        </div>
      </div>
    </div>
  )
}

