        answer,
        model: 'fixed:k_mom_picks',
        lang: 'en',
        ip,
        country,
        user_agent: userAgent,
        referer,
        path: req.nextUrl.pathname,
      } as any)

      const insertOk = !insErr
      const insertError = insErr
        ? `${(insErr as any).code ?? ''}:${(insErr as any).message ?? 'insert_failed'}${
            (insErr as any)?.details ? ` | ${(insErr as any).details}` : ''
          }`
        : null

      stage = 'ok_fixed'
      return NextResponse.json(
        {
          answer,
          requestId,
          ms: Date.now() - startedAt,
          userId,
          email,
          sessionId,
          insertOk,
          insertError,
          authUserDetected,
          authError,
          kMomMode: true,
        },
        { status: 200 }
      )
    }

    stage = 'load_prev_context'
    let prevContext = ''
    try {
      const q = supabase
        .from('chat_logs')
        .select('question, answer')
        .order('created_at', { ascending: false })
        .limit(2)

      const { data } = userId ? await q.eq('user_id', userId) : await q.eq('session_id', sessionId)
      if (data && data.length) {
        prevContext = data
          .map((r: any) => `Q: ${r?.question ?? ''}\nA: ${r?.answer ?? ''}`)
          .join('\n\n')
      }
    } catch {
      prevContext = ''
    }

    stage = 'count_today'
    const today = new Date().toISOString().slice(0, 10)
    let greetedToday = false
    try {
      const q = supabase
        .from('chat_logs')
        .select('id', { count: 'exact', head: true })
        .gte('created_at', `${today}T00:00:00Z`)

      const { count } = userId ? await q.eq('user_id', userId) : await q.eq('session_id', sessionId)
      greetedToday = (count ?? 0) > 0
    } catch {
      greetedToday = false
    }

    stage = 'compose_system'
    const base = systemFromClient?.trim() || getSystemPrompt({ greetedToday, prevContext })
    const kParentingRule = `
You answer in **English only**.
If the user asks about **K-parenting / Korean parenting / parenting in Korea**:
- Emphasize benefits and strengths first.
- Mention at most **one** brief, minimized caution framed constructively.
- Keep the total answer under **~2000 bytes**.
- Do not repeat the final sentence. End cleanly.`.trim()

    const system = `${base}\n\n${kParentingRule}`.trim()

    stage = 'openai_first'
    const model = process.env.OPENAI_MODEL ?? 'gpt-4o-mini'
    const { part, finish } = await openAIChat({
      model,
      system,
      question: rawQuestion,
      temperature: 0.4,
      max_tokens: 1100,
      stop: ['[END]'],
    })

    let answer = String(part || '').replace(/\s*\[END\]\s*$/, '')

    if (finish !== 'stop') {
      stage = 'openai_continue'
      try {
        const cont = await openAIChat({
          model,
          system,
          question: `${rawQuestion}\n\n(Continue. Do not repeat prior text. Conclude succinctly. End with [END].)`,
          temperature: 0.4,
          max_tokens: 700,
          stop: ['[END]'],
        })
        const tail = (cont.part || '').replace(/\s*\[END\]\s*$/, '')
        if (tail) answer += tail
      } catch {
        // ignore
      }
    }

    stage = 'trim'
    answer = trimToBytes(answer, 2000)

    stage = 'insert_logs'
    const { error: insErr } = await admin.from('chat_logs').insert({
      user_id: userId,
      email,
      session_id: sessionId,
      question: rawQuestion,
      answer,
      model,
      lang: 'en',
      ip,
      country,
      user_agent: userAgent,
      referer,
      path: req.nextUrl.pathname,
    } as any)

    const insertOk = !insErr
    const insertError = insErr
      ? `${(insErr as any).code ?? ''}:${(insErr as any).message ?? 'insert_failed'}${
          (insErr as any)?.details ? ` | ${(insErr as any).details}` : ''
        }`
      : null

    stage = 'ok'
    return NextResponse.json(
      {
        answer,
        requestId,
        ms: Date.now() - startedAt,
        userId,
        email,
        sessionId,
        insertOk,
        insertError,
        authUserDetected,
        authError,
        kMomMode: false,
      },
      { status: 200 }
    )
  } catch (e: any) {
    return NextResponse.json(
      {
        error: 'server_error',
        requestId,
        stage,
        message: String(e?.message ?? e).slice(0, 800),
      },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import type { Database } from '@/lib/database.types'

export const runtime = 'nodejs'
export const dynamic = 'force-dynamic'

function admin() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL!
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY!
  return createClient<Database>(url, key, {
    auth: { persistSession: false, autoRefreshToken: false },
  })
}

function isValidEmail(v: string) {
  const s = (v ?? '').trim()
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s)
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const teamId = String(body.teamId ?? '').trim()
    const email = String(body.email ?? '').trim().toLowerCase()

    if (!teamId || !isValidEmail(email)) {
      return NextResponse.json({ error: 'invalid_input' }, { status: 400 })
    }

    const sb = admin()

    // ??teamId濡??쒖꽦 ?대깽??李얘린
    const { data: ev, error: evErr } = await (sb as any)
      .from('giveaway_events')
      .select('id')
      .eq('team_id', teamId)
      .eq('is_active', true)
      .order('created_at', { ascending: false })
      .limit(1)
      .maybeSingle()

    if (evErr) {
      return NextResponse.json({ error: evErr.message }, { status: 500 })
    }

    const eventId = String(ev?.id ?? '').trim()
    if (!eventId) {
      return NextResponse.json({ error: 'no_active_event' }, { status: 400 })
    }

    const { error: insErr } = await (sb as any).from('giveaway_entries').insert({
      event_id: eventId,
      team_id: teamId,
      email,
    })

    // ??以묐났 ?묐え (unique 嫄몃젮?덉쑝硫?
    if (insErr && (insErr as any).code === '23505') {
      return NextResponse.json({ alreadyEntered: true })
    }

    if (insErr) {
      return NextResponse.json({ error: insErr.message }, { status: 500 })
    }

    return NextResponse.json({ ok: true })
  } catch (e: any) {
    return NextResponse.json({ error: String(e?.message ?? e) }, { status: 500 })
  }
}

