    // ???묐떟 媛앹껜 癒쇱? 留뚮뱾怨? set-cookie媛 ?꾩슂?섎㈃ ?ш린???ｋ뒗??r
    const res = NextResponse.json({ ok: false }, { status: 200 })

    // ??Next 16 cookies() ??? getAll/setAll ?⑦꽩
    const supabase = createServerClient<Database>(supabaseUrl, supabaseAnon, {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => {
            cookieStore.set(name, value, options)
            res.cookies.set(name, value, options)
          })
        },
      },
    })

    // 1) 濡쒓렇??泥댄겕 (荑좏궎 湲곕컲 ?몄뀡)
    const { data: userData, error: userError } = await supabase.auth.getUser()
