    // 2) draft id 泥댄겕
    const body = await _req.json().catch(() => null)
    const draftId = cookieStore.get(DRAFT_COOKIE)?.value || body?.draft_id
    if (!draftId) {
      return NextResponse.json({ ok: false, error: 'no draft' }, { status: 400 })
    }

    // 3) draft 濡쒕뱶 (?쒕퉬??濡?
