import { NextResponse } from 'next/server'
import { cookies } from 'next/headers'
import { createServerClient } from '@supabase/ssr'
import type { Database, Tables } from '@/lib/database.types'

export const runtime = 'nodejs'
export const dynamic = 'force-dynamic'
export const revalidate = 0

const REWARDS = [
  100, 100, 100, 100, 100, 100, // 1-6
  300, // 7
  100, 100, 100, 100, 100, 100, // 8-13
  600, // 14
]

// ??UTC 湲곗? ?좎쭨(YYYY-MM-DD)
function ymdInUTC(d = new Date()) {
  return d.toISOString().slice(0, 10)
}

function addDaysUTC(ymd: string, delta: number) {
  const [y, m, d] = ymd.split('-').map((x) => Number(x))
  const dt = new Date(Date.UTC(y, m - 1, d))
  dt.setUTCDate(dt.getUTCDate() + delta)
  const y2 = dt.getUTCFullYear()
  const m2 = String(dt.getUTCMonth() + 1).padStart(2, '0')
  const d2 = String(dt.getUTCDate()).padStart(2, '0')
  return `${y2}-${m2}-${d2}`
}

function mustEnv(name: string) {
  const v = (process.env[name] || '').trim()
  if (!v) throw new Error(`Missing env: ${name}`)
  return v
}

async function createSupabaseServer() {
  const url = mustEnv('NEXT_PUBLIC_SUPABASE_URL')
  const anon = mustEnv('NEXT_PUBLIC_SUPABASE_ANON_KEY')

  const cookieStore = await cookies()

  return createServerClient<Database>(url, anon, {
    cookies: {
      get(name: string) {
        return cookieStore.get(name)?.value
      },
      set(name: string, value: string, options: any) {
        try {
          cookieStore.set({ name, value, ...options })
        } catch {}
      },
      remove(name: string, options: any) {
        try {
          cookieStore.set({ name, value: '', ...options, maxAge: 0 })
        } catch {}
      },
    },
  })
}

// ??"?ㅻ뒛(UTC)" 吏덈Ц 1媛??댁긽 ?덈뒗吏 泥댄겕 (DB?먯꽌 諛붾줈)
async function hasQuestionTodayUTC(
  supabase: Awaited<ReturnType<typeof createSupabaseServer>>,
  userId: string,
  todayUtc: string
) {
  const { count, error } = await supabase
    .from('chat_logs')
    .select('id', { count: 'exact', head: true })
    .eq('user_id', userId)
    .gte('created_at', `${todayUtc}T00:00:00.000Z`)
    .not('question', 'is', null)

  if (error) return false
  return (count ?? 0) > 0
}

export async function POST() {
  const supabase = await createSupabaseServer()

  const {
    data: { user },
    error: userErr,
  } = await supabase.auth.getUser()

  if (userErr || !user) {
    return NextResponse.json({ ok: false, reason: 'not_authenticated' }, { status: 401 })
  }

  // ???ㅻ뒛/?댁젣 紐⑤몢 UTC
  const today = ymdInUTC(new Date())
  const yesterday = addDaysUTC(today, -1)

  // 1) ?ㅻ뒛 吏덈Ц ?덈뒗吏
  const okQuestion = await hasQuestionTodayUTC(supabase, user.id, today)
  if (!okQuestion) {
    return NextResponse.json({ ok: false, reason: 'no_question_today', today }, { status: 200 })
  }

  // 2) profiles?먯꽌 ?곗씠??媛?몄삤湲?r
  type ProfilePick = Pick<Tables<'profiles'>, 'points' | 'reward_last_date' | 'reward_streak'>

  const { data: prof, error: profErr } = await supabase
    .from('profiles')
    .select('points, reward_last_date, reward_streak')
    .eq('id', user.id)
    .maybeSingle()

  if (profErr) {
    return NextResponse.json(
      { ok: false, reason: 'db_error', error: String(profErr.message ?? profErr) },
      { status: 200 }
    )
  }

  const p = (prof as ProfilePick | null) ?? null
  const currentPoints = Number(p?.points ?? 0)
  const lastDate = (p?.reward_last_date ?? null) as string | null // ??臾몄옄??YYYY-MM-DD)?쇨퀬 媛??r
  const lastStreak = Number(p?.reward_streak ?? 0)

  // 3) ?대? ?ㅻ뒛 諛쏆븯?쇰㈃ 醫낅즺
  if (lastDate === today) {
    return NextResponse.json({ ok: false, reason: 'already_claimed', today }, { status: 200 })
  }

  // 4) reward_claims 以묐났 諛⑹?(?ㅻ뒛 record ?덉쑝硫?醫낅즺)
  const { data: claimedRow, error: chkErr } = await supabase
    .from('reward_claims')
    .select('id')
    .eq('user_id', user.id)
    .eq('day', today)
    .maybeSingle()

  if (chkErr) {
    return NextResponse.json(
      { ok: false, reason: 'db_error', error: String(chkErr.message ?? chkErr) },
      { status: 200 }
    )
  }

  if (claimedRow) {
    return NextResponse.json({ ok: false, reason: 'already_claimed', today }, { status: 200 })
  }

  // 5) ?곗냽 streak 怨꾩궛 (UTC 湲곗?)
  const nextTotalStreak = lastDate === yesterday ? Math.max(1, lastStreak + 1) : 1

  // 6) 14???ъ씠???ъ???1~14)
  const cyclePos = ((nextTotalStreak - 1) % 14) + 1
  const rewardPoints = REWARDS[cyclePos - 1] ?? 100

  // 7) reward_claims insert (UTC day瑜?紐낆떆?곸쑝濡????
  const { error: insErr } = await supabase.from('reward_claims').insert({
    user_id: user.id,
    day: today,
    points: rewardPoints, // ?뚯씠釉붿뿉 ?덉쑝硫???? ?놁쑝硫?吏?뚮룄 ??r
  } as any)

  if (insErr) {
    return NextResponse.json(
      { ok: false, reason: 'db_error', error: String(insErr.message ?? insErr) },
      { status: 200 }
    )
  }

  // 8) profiles ?낅뜲?댄듃
  const nextPoints = currentPoints + rewardPoints

  const { error: updErr } = await supabase
    .from('profiles')
    .update({
      points: nextPoints,
      reward_last_date: today,
      reward_streak: nextTotalStreak,
    })
    .eq('id', user.id)

  if (updErr) {
    return NextResponse.json(
      { ok: false, reason: 'db_error', error: String(updErr.message ?? updErr) },
      { status: 200 }
    )
  }

  // 9) UI 媛깆떊??board
  const board = Array.from({ length: 14 }, (_, i) => i < cyclePos)

  return NextResponse.json({
    ok: true,
    today,
    points_added: rewardPoints,
    streak: cyclePos,
    board,
    total_points: nextPoints,
  })
}

// src/app/api/rewards/status/route.ts
import { NextResponse } from 'next/server'
import { cookies } from 'next/headers'
import { createServerClient } from '@supabase/ssr'
import type { Database } from '@/lib/database.types'

export const runtime = 'nodejs'
export const dynamic = 'force-dynamic'
export const revalidate = 0

function ymdInUTC(d = new Date()) {
  return d.toISOString().slice(0, 10)
}

function addDaysUTC(ymd: string, delta: number) {
  const [y, m, d] = ymd.split('-').map((x) => Number(x))
  const dt = new Date(Date.UTC(y, m - 1, d))
  dt.setUTCDate(dt.getUTCDate() + delta)
  const y2 = dt.getUTCFullYear()
  const m2 = String(dt.getUTCMonth() + 1).padStart(2, '0')
  const d2 = String(dt.getUTCDate()).padStart(2, '0')
  return `${y2}-${m2}-${d2}`
}

function mustEnv(name: string) {
  const v = (process.env[name] || '').trim()
  if (!v) throw new Error(`Missing env: ${name}`)
  return v
}

async function createSupabaseServer() {
  const url = mustEnv('NEXT_PUBLIC_SUPABASE_URL')
  const anon = mustEnv('NEXT_PUBLIC_SUPABASE_ANON_KEY')
  const cookieStore = await cookies()

  return createServerClient<Database>(url, anon, {
    cookies: {
      get(name: string) {
        return cookieStore.get(name)?.value
      },
      set(name: string, value: string, options: any) {
        try {
          cookieStore.set({ name, value, ...options })
        } catch {}
      },
      remove(name: string, options: any) {
        try {
          cookieStore.set({ name, value: '', ...options, maxAge: 0 })
        } catch {}
      },
    },
  })
}

export async function GET() {
  const today = ymdInUTC(new Date())

  let supabase: Awaited<ReturnType<typeof createSupabaseServer>>
  try {
    supabase = await createSupabaseServer()
  } catch (e: any) {
    return NextResponse.json({
      ok: false,
      reason: 'config_error',
      today,
      claimed_today: false,
      streak: 0,
      board: Array.from({ length: 14 }, () => false),
      error: String(e?.message ?? e),
    })
  }

  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({
      ok: true,
      reason: 'not_authenticated',
      today,
      claimed_today: false,
      streak: 0,
      board: Array.from({ length: 14 }, () => false),
    })
  }

  const { data, error } = await supabase
    .from('reward_claims')
    .select('day')
    .eq('user_id', user.id)
    .order('day', { ascending: false })
    .limit(40)

  if (error) {
    return NextResponse.json({
      ok: false,
      reason: 'db_error',
      today,
      claimed_today: false,
      streak: 0,
      board: Array.from({ length: 14 }, () => false),
      error: String(error.message ?? error),
    })
  }

  const days = (data ?? []).map((r: any) => String(r.day)).filter(Boolean)

  if (days.length === 0) {
    return NextResponse.json({
      ok: true,
      today,
      claimed_today: false,
      streak: 0,
      board: Array.from({ length: 14 }, () => false),
    })
  }

  const last = days[0]
  const yesterday = addDaysUTC(today, -1)
  const isLastToday = last === today
  const isLastYesterday = last === yesterday

  if (!isLastToday && !isLastYesterday) {
    return NextResponse.json({
      ok: true,
      today,
      claimed_today: false,
      streak: 0,
      board: Array.from({ length: 14 }, () => false),
    })
  }

  const set = new Set(days)
  let streakTotal = 0
  let cursor = last
  while (set.has(cursor)) {
    streakTotal += 1
    cursor = addDaysUTC(cursor, -1)
    if (streakTotal > 365) break
  }

  const cyclePos = ((streakTotal - 1) % 14) + 1
  const board = Array.from({ length: 14 }, (_, i) => i < cyclePos)

  return NextResponse.json({
    ok: true,
    today,
    claimed_today: isLastToday,
    streak: cyclePos,
    board,
  })
}

