// src/app/kyk/KYKLoginModal.tsx
'use client'

import { createClientComponentClient } from '@supabase/auth-helpers-nextjs'
import { useState } from 'react'
import type { Database } from '@/lib/database.types'

const TEXT = '#0e0e0e'
const MUTED = '#b4b4b4'
const BORDER = '#eeeeee'
const BTN = '#3497f3'

export default function KYKLoginModal({
  open,
  onClose,
  onAfterLogin,
  dict,
}: {
  open: boolean
  onClose: () => void
  onAfterLogin: () => Promise<void>
  dict: any
}) {
  const supabase = createClientComponentClient<Database>()
  const [busy, setBusy] = useState(false)
  const [error, setError] = useState<string | null>(null)

  if (!open) return null

  async function onGoogle() {
    setError(null)
    setBusy(true)

    try {
      // ??濡쒓렇?????뚯븘???꾩튂瑜?/kyk/step3 濡?怨좎젙
      // 荑좏궎瑜??ъ슜??auth/callback ?쇱슦?몄뿉???쎌쓣 ???덈룄濡???n      document.cookie = 'kyk_auth_return=/kyk/step3?after=login; path=/; max-age=300; SameSite=Lax'
      const callbackUrl = new URL('/auth/callback', window.location.origin)

      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: { 
          redirectTo: callbackUrl.toString(),
          queryParams: { prompt: 'select_account' }
        },
      })

      if (error) setError(error.message)
      // ?깃났 ?쒖뿉??釉뚮씪?곗?媛 諛붾줈 OAuth濡??대룞?섎?濡??ш린?????????놁쓬
    } finally {
      setBusy(false)
    }
  }

  // ???ъ슜?먭? ?쒖씠誘?濡쒓렇???섏뼱 ?덈뒗 ?곹깭?앸줈 紐⑤떖???대떎硫?n  // OK 踰꾪듉 ?꾨? ??諛붾줈 claim 泥섎━?섍퀬 寃곌낵濡?蹂대깂
  async function onOkIfAlreadyLoggedIn() {
    setError(null)
    setBusy(true)
    try {
      await onAfterLogin()
    } catch (e: any) {
      setError(e?.message ?? 'Failed to continue.')
    } finally {
      setBusy(false)
    }
  }

  return (
    <div
      className="fixed inset-0 z-[9999] flex items-center justify-center px-4"
      style={{ background: 'rgba(0,0,0,0.35)' }}
      role="dialog"
      aria-modal="true"
    >
      <div className="w-full max-w-sm rounded-lg bg-white p-5">
        <div className="text-[16px] font-medium" style={{ color: TEXT }}>
          {dict.title}
        </div>

        <div className="mt-2 text-[13px]" style={{ color: MUTED }}>
          {dict.desc}
        </div>

        {error && (
          <div className="mt-3 text-[12px]" style={{ color: '#d00' }}>
            {error}
          </div>
        )}

        <div className="mt-5 flex gap-2">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 rounded-md border px-4 py-2 text-[14px] font-medium"
            style={{ borderColor: BORDER, color: TEXT }}
            disabled={busy}
          >
            {dict.btn_cancel}
          </button>

          <button
            type="button"
            onClick={onGoogle}
            className="flex-1 rounded-md px-4 py-2 text-[14px] font-medium"
            style={{ background: BTN, color: 'white' }}
            disabled={busy}
          >
            {busy ? dict.btn_opening : dict.btn_ok}
          </button>
        </div>

        {/* ?대? 濡쒓렇?몃맂 ?ъ슜?먮㈃: 洹몃깷 怨꾩냽 吏꾪뻾 踰꾪듉???쒓났(?듭뀡) */}
        <button
          type="button"
          onClick={onOkIfAlreadyLoggedIn}
          className="mt-3 w-full rounded-md border px-4 py-2 text-[13px] font-medium"
          style={{ borderColor: BORDER, color: TEXT }}
          disabled={busy}
        >
          {dict.btn_continue}
        </button>
      </div>
    </div>
  )
}

