const BORDER = '#eeeeee'
const BTN = '#3497f3'

export default function GateClient({ dict }: { dict: any }) {
  const router = useRouter()
  const supabase = useMemo(() => createClientComponentClient<Database>(), [])

  const [loading, setLoading] = useState(true)
  const [needLogin, setNeedLogin] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [busyLogin, setBusyLogin] = useState(false)

  async function claim() {
    setError(null)

    const res = await fetch('/api/kyk/claim', { method: 'POST' })
    const json = await res.json().catch(() => ({}))

    if (res.ok && json?.ok) {
      router.replace('/kyk/result')
      return
    }

    if (res.status === 401) {
      setNeedLogin(true)
      return
    }

    const detail = json?.error ?? `HTTP ${res.status}`
    setError(detail)
  }

  useEffect(() => {
    ;(async () => {
      await claim()
      setLoading(false)
    })()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  async function onGoogleLogin() {
    try {
      setBusyLogin(true)
      setError(null)

      document.cookie = 'kyk_auth_return=/kyk/gate; path=/; max-age=300; SameSite=Lax'
      const callbackUrl = new URL('/auth/callback', window.location.origin)

      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: callbackUrl.toString(),
          queryParams: {
            prompt: 'select_account',
          },
        },
      })

      if (error) {
        setError(error.message)
      }
    } finally {
      setBusyLogin(false)
    }
  }

  return (
    <main className="min-h-screen bg-white" style={{ color: TEXT }}>
      <div className="mx-auto max-w-5xl px-4 py-10">
        <h1 className="text-[24px] font-medium leading-tight">{dict.title}</h1>
        <p className="mt-3 text-[14px]" style={{ color: MUTED }}>
          {dict.loading_msg}
        </p>

        <div className="mt-8 border-t" style={{ borderColor: BORDER }} />

        <section className="mt-10">
          {loading ? (
            <p className="text-[14px]" style={{ color: MUTED }}>
              {dict.loading}
            </p>
          ) : error ? (
            <p className="text-[13px]" style={{ color: '#d00' }}>
              {error}
            </p>
          ) : null}
        </section>
      </div>

      {needLogin && (
        <div
          className="fixed inset-0 z-[9999] flex items-center justify-center px-4"
          style={{ background: 'rgba(0,0,0,0.35)' }}
          role="dialog"
          aria-modal="true"
        >
          <div className="w-full max-w-sm rounded-lg bg-white p-5">
            <div className="text-[16px] font-medium" style={{ color: TEXT }}>
              {dict.modal_title}
            </div>

            <div className="mt-2 text-[13px]" style={{ color: MUTED }}>
              {dict.modal_desc}
            </div>

            {error && (
              <div className="mt-3 text-[12px]" style={{ color: '#d00' }}>
                {error}
              </div>
            )}

            <div className="mt-5 flex gap-2">
              <button
                type="button"
                onClick={() => router.replace('/kyk')}
                className="flex-1 rounded-md border px-4 py-2 text-[14px] font-medium"
                style={{ borderColor: BORDER, color: TEXT }}
                disabled={busyLogin}
              >
                {dict.btn_back}
              </button>

              <button
                type="button"
                onClick={onGoogleLogin}
                className="flex-1 rounded-md px-4 py-2 text-[14px] font-medium"
                style={{ background: BTN, color: 'white' }}
                disabled={busyLogin}
              >
                {busyLogin ? dict.btn_opening : dict.btn_ok}
              </button>
            </div>
          </div>
        </div>
      )}
    </main>
  )
}

