// src/app/news/page.tsx (Server Component)
import Link from 'next/link'
import { cookies } from 'next/headers'
import { createServerClient } from '@supabase/ssr'
import type { Database } from '@/lib/database.types'
import PageHeader from '@/components/layout/PageHeader'
import { getDictionary, getLocale } from '@/i18n'
import { resolveI18n } from '@/lib/i18nFallback'

export const dynamic = 'force-dynamic'
export const revalidate = 0

type NewsRow = {
  id: string
  title: string
  title_i18n?: any
  slug: string
  created_at: string | null
  cover_image_url: string | null
  category?: string | null
}

async function createSupabaseServer() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const anon = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
  if (!url || !anon) throw new Error('Missing NEXT_PUBLIC_SUPABASE_URL / NEXT_PUBLIC_SUPABASE_ANON_KEY')

  const cookieStore = await cookies()

  return createServerClient<Database>(url, anon, {
    cookies: {
      get(name: string) {
        return cookieStore.get(name)?.value
      },
      set(name: string, value: string, options: any) {
        try {
          cookieStore.set({ name, value, ...options })
        } catch {}
      },
      remove(name: string, options: any) {
        try {
          cookieStore.set({ name, value: '', ...options, maxAge: 0 })
        } catch {}
      },
    },
  })
}

function formatDate(d: string | null) {
  if (!d) return ''
  const dt = new Date(d)
  if (Number.isNaN(dt.getTime())) return ''
  return dt.toLocaleDateString('en-US')
}

async function fetchNewsList(sb: Awaited<ReturnType<typeof createSupabaseServer>>) {
  const base = 'id, title, title_i18n, slug, created_at, cover_image_url'
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const anySb: any = sb

  const try1 = await anySb.from('news_posts').select(`${base}, category`).order('created_at', { ascending: false })
  if (!try1?.error) return (try1.data ?? []) as NewsRow[]

  const try2 = await sb.from('news_posts').select(base).order('created_at', { ascending: false })
  if (try2.error) return []
  return ((try2.data as any) ?? []) as NewsRow[]
}

function CategoryPill({ label }: { label: string }) {
  return (
    <span className="inline-flex items-center h-7 px-3 rounded bg-[#f2f2f2] text-[#8a8a8a] text-[13px] font-medium">
      {label}
    </span>
  )
}

export default async function NewsPage() {
  const supabase = await createSupabaseServer()
  const locale = await getLocale()
  const news = await fetchNewsList(supabase)
  const t = await getDictionary('news')

  return (
    <main className="min-h-screen bg-white text-[#0e0e0e]">
      <div className="mx-auto max-w-5xl px-4 py-10">
        {/* ??怨듯넻 ?ㅻ뜑 ?곸슜: ?ㅻ챸 ?꾨옒 ?뚯깋以??먮룞 */}
        <PageHeader title={t.title} subtitle={t.subtitle} />

        {/* ??湲곗〈 mt-10 border-t wrapper ?쒓굅 (以묐났 諛⑹?) */}
        {news.length === 0 ? (
          <div className="py-16 text-[#b4b4b4] text-[15px] font-medium">{t.no_news}</div>
        ) : (
          <ul>
            {news.map((n) => {
              const date = formatDate(n.created_at)
              const category = (n.category && String(n.category).trim()) || 'Research'
              const cover = n.cover_image_url ? String(n.cover_image_url).trim() : ''
              const resolvedTitle = resolveI18n(n.title, n.title_i18n, locale)

              return (
                <li key={n.id} className="border-b border-[#eeeeee]">
                  <Link href={`/news/${n.slug}`} className="block py-10 hover:bg-[#fafafa] transition">
                    <div className="flex flex-row items-start gap-5">
                      <div className="shrink-0 w-[120px] sm:w-[220px]">
                        <div className="w-full aspect-square bg-[#d9d9d9] overflow-hidden">
                          {cover ? (
                            // eslint-disable-next-line @next/next/no-img-element
                            <img src={cover} alt={n.title} className="w-full h-full object-cover" loading="lazy" />
                          ) : null}
                        </div>
                      </div>

                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-3 flex-wrap">
                          <CategoryPill label={category} />
                          <div className="text-[15px] text-[#b4b4b4] font-Light">{date}</div>
                        </div>

                        <h2 className="mt-3 text-[20px] sm:text-[20px] leading-tight line-clamp-3">{resolvedTitle}</h2>
                      </div>
                    </div>
                  </Link>
                </li>
              )
            })}
          </ul>
        )}
      </div>
    </main>
  )
}

// src/app/reward/RewardClient.tsx
'use client'

import { useCallback, useEffect, useMemo, useState } from 'react'
import { useAuthUser, useSupabase } from '@/app/providers'

type RewardsStatusResponse =
  | {
      ok: true
      today: string
      claimed_today: boolean
      streak: number // 1~14 (cyclePos)
      board: boolean[] // length 14
      reason?: string
    }
  | {
      ok: false
      today: string
      claimed_today: boolean
      streak: number
      board: boolean[]
      reason: string
      error?: string
    }

type ClaimApiResponse =
  | {
      ok: true
      // ??claim route媛 踰꾩쟾???곕씪 ?ㅺ? ?ㅻ? ???덉뼱???????섏슜
      points_added?: number
      cycle_pos?: number
      streak_total?: number
      today?: string
      streak?: number
      board?: boolean[]
      total_points?: number
    }
  | {
      ok: false
      reason:
        | 'not_authenticated'
        | 'no_question_today'
        | 'already_claimed'
        | 'db_error'
        | 'unknown'
      error?: string
      today?: string
    }

type ClaimState =
  | { type: 'idle' }
  | { type: 'ok'; pointsAdded: number; cyclePos: number }
  | { type: 'already_claimed' }
  | { type: 'no_question_today' }
  | { type: 'not_authenticated' }
  | { type: 'http_error'; status: number; message: string }
  | { type: 'network_error'; message: string }

const REWARDS = [
  100, 100, 100, 100, 100, 100, // 1-6
  300, // 7
  100, 100, 100, 100, 100, 100, // 8-13
  600, // 14
]

function pointsForDay(day: number) {
  // day: 1~14
  return REWARDS[day - 1] ?? 100
}

function format(n: number) {
  try {
    return n.toLocaleString('en-US')
  } catch {
    return String(n)
  }
}

function stripTrailingSlash(s: string) {
  return s.replace(/\/$/, '')
}

function getSiteOrigin() {
  const envSite = (process.env.NEXT_PUBLIC_SITE_URL || '').trim()
  if (envSite) return stripTrailingSlash(envSite)
  if (typeof window !== 'undefined') return window.location.origin
  return ''
}

async function safeJson(res: Response) {
  const text = await res.text()
  try {
    return JSON.parse(text)
  } catch {
    return { raw: text }
  }
}

/** ??紐⑤컮??5 / 5 / 4 怨좎젙 ?덉씠?꾩썐???꾪빐 3以꾨줈 履쇨갔 */
function split14ForMobile(items: any[]) {
  return [items.slice(0, 5), items.slice(5, 10), items.slice(10, 14)]
}

export default function RewardClient() {
  const { user } = useAuthUser()
  const supabase = useSupabase()

  const [loading, setLoading] = useState(false)
  const [toast, setToast] = useState('')
  const [showLoginModal, setShowLoginModal] = useState(false)

  const [claimState, setClaimState] = useState<ClaimState>({ type: 'idle' })

  const [myPoints, setMyPoints] = useState<number | null>(null)
  const [myStreak, setMyStreak] = useState<number | null>(null)

  // ??蹂대뱶 ?곹깭
  const [board, setBoard] = useState<boolean[]>(Array.from({ length: 14 }, () => false))
  const [cyclePos, setCyclePos] = useState<number>(0) // 0?대㈃ ?꾩쭅 ?쒖옉 ??r
  const [claimedToday, setClaimedToday] = useState<boolean>(false)

  const [modal, setModal] = useState<{ open: boolean; title: string; body: string }>({
    open: false,
    title: '',
    body: '',
  })

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(''), 2500)
    return () => clearTimeout(t)
  }, [toast])

  useEffect(() => {
    if (user) setShowLoginModal(false)
  }, [user])

  const getAuthRedirectTo = useCallback(() => {
    const base = getSiteOrigin()
    return `${base}/auth/callback?next=/reward`
  }, [])

  const loginGoogle = useCallback(async () => {
    const redirectTo = getAuthRedirectTo()
    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo },
    })
  }, [supabase, getAuthRedirectTo])

  const loadMySummary = useCallback(async () => {
    if (!user) {
      setMyPoints(null)
      setMyStreak(null)
      return
    }

    const { data, error } = await supabase
      .from('profiles')
      .select('points, reward_streak')
      .eq('id', user.id)
      .maybeSingle()

    if (error) {
      console.error('[profiles summary] error:', error)
      return
    }

    setMyPoints(Number((data as any)?.points ?? 0))
    setMyStreak(Number((data as any)?.reward_streak ?? 0))
  }, [supabase, user])

  const loadRewardStatus = useCallback(async () => {
    try {
      const res = await fetch('/api/rewards/status', { method: 'GET', cache: 'no-store' })
      const json = (await safeJson(res)) as RewardsStatusResponse

      // status??200?쇰줈 ?듭씪?쒕떎怨??덉쑝??res.ok ?щ?蹂대떒 payload ?곗꽑
      const nextBoard = Array.isArray((json as any)?.board) ? (json as any).board : []
      const nextStreak = Number((json as any)?.streak ?? 0)
      const nextClaimedToday = Boolean((json as any)?.claimed_today ?? false)

      if (nextBoard.length === 14) setBoard(nextBoard)
      else setBoard(Array.from({ length: 14 }, () => false))

      setCyclePos(nextStreak)
      setClaimedToday(nextClaimedToday)
    } catch (e) {
      console.error('[rewards status] error:', e)
      // 議곗슜???ㅽ뙣 泥섎━
    }
  }, [])

  useEffect(() => {
    void loadMySummary()
  }, [loadMySummary])

  useEffect(() => {
    void loadRewardStatus()
  }, [loadRewardStatus])

  const onClaim = useCallback(async () => {
    if (!user) {
      setShowLoginModal(true)
      return
    }

    setClaimState({ type: 'idle' })
    setLoading(true)

    try {
      const res = await fetch('/api/rewards/claim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        cache: 'no-store',
      })

      const json = (await safeJson(res)) as any

      if (!res.ok) {
        const reason = String(json?.reason ?? '')
        if (res.status === 401 || reason === 'not_authenticated') {
          setClaimState({ type: 'not_authenticated' })
          setModal({ open: true, title: 'Login required', body: 'Please login and try again.' })
          return
        }

        setClaimState({
          type: 'http_error',
          status: res.status,
          message: String(json?.error ?? json?.reason ?? 'http_error'),
        })
        setModal({ open: true, title: 'Error', body: 'Something went wrong. Please try again.' })
        return
      }

      const payload = json as ClaimApiResponse

      if (payload?.ok === true) {
        const add = Number((payload as any)?.points_added ?? 0)

        // ??cyclePos ?ㅺ? cycle_pos / streak ?????????덉쓬
        const nextCycle = Number((payload as any)?.cycle_pos ?? (payload as any)?.streak ?? cyclePos ?? 1)

        setClaimState({ type: 'ok', pointsAdded: add, cyclePos: nextCycle })

        // points/streak 利됱떆 諛섏쁺
        setMyPoints((prev) => (prev ?? 0) + add)
        setMyStreak((prev) => {
          // profiles.reward_streak???쒖킑 ?곗냽?쇄앹씤???ш린??UI?먯꽌 ???섎??놁뼱???좎?
          // ???湲곗〈 媛??덉쑝硫?+1 ?뺣룄濡쒕쭔 諛섏쁺(?쒕쾭媛 authoritative)
          return prev ?? null
        })

        // ??蹂대뱶 利됱떆 諛섏쁺 (claim??board ?대젮二쇰㈃ 洹멸굅 ?ъ슜)
        if (Array.isArray((payload as any)?.board) && (payload as any).board.length === 14) {
          setBoard((payload as any).board)
        } else {
          // ?놁쑝硫?status ?ㅼ떆 濡쒕뱶
          void loadRewardStatus()
        }

        setCyclePos(nextCycle)
        setClaimedToday(true)

        window.dispatchEvent(new Event('points:refresh'))
        setToast(add > 0 ? `??+${add}p` : '??Checked in')
        return
      }

      const reason = String((payload as any)?.reason ?? '')

      if (reason === 'already_claimed') {
        setClaimState({ type: 'already_claimed' })
        setModal({ open: true, title: 'Already claimed', body: 'You already claimed today.' })
        setClaimedToday(true)
        return
      }

      if (reason === 'no_question_today') {
        setClaimState({ type: 'no_question_today' })
        setModal({
          open: true,
          title: 'Action required',
          body: 'Please ask at least one question in the AI Parenting Coach and then claim.',
        })
        return
      }

      if (reason === 'not_authenticated') {
        setClaimState({ type: 'not_authenticated' })
        setModal({ open: true, title: 'Login required', body: 'Please login and try again.' })
        return
      }

      setClaimState({ type: 'http_error', status: 200, message: reason || 'unknown' })
      setModal({ open: true, title: 'Error', body: 'Something went wrong. Please try again.' })
    } catch (e: any) {
      setClaimState({ type: 'network_error', message: String(e?.message ?? e) })
      setModal({ open: true, title: 'Error', body: 'Network error. Please try again.' })
    } finally {
      setLoading(false)
      // claim ?댄썑?먮뒗 status ??踰????숆린???덉쟾)
      void loadRewardStatus()
      void loadMySummary()
    }
  }, [user, supabase, cyclePos, loadRewardStatus, loadMySummary])

  const summaryText = useMemo(() => {
    if (!user) return null
    const s = myStreak ?? 0
    const p = myPoints ?? 0
    return `Streak: ${s} days 쨌 Points: ${format(p)}`
  }, [user, myPoints, myStreak])

  // ??蹂대뱶 ?뚮뜑???곗씠??r
  const cells = useMemo(() => {
    return Array.from({ length: 14 }, (_, i) => {
      const day = i + 1
      const cleared = Boolean(board?.[i])
      const isTodayCell = claimedToday && cyclePos === day // ?ㅻ뒛 claim ?덈떎硫??꾩옱 cyclePos媛 ?ㅻ뒛 移?r
      return { day, cleared, isTodayCell, points: pointsForDay(day) }
    })
  }, [board, cyclePos, claimedToday])

  const mobileRows = useMemo(() => split14ForMobile(cells), [cells])

  const StampCell = ({ day, cleared, isTodayCell, points }: any) => {
    return (
      <div className="relative rounded-lg border border-[#e9e9e9] bg-white px-2 py-3 text-center">
        {/* Day label */}
        <div className="text-[12px] font-semibold text-[#1e1e1e]">Day {day}</div>

        {/* P circle */}
        <div className="mt-2 flex items-center justify-center">
          <div
            className={[
              'h-8 w-8 rounded-full flex items-center justify-center text-[12px] font-bold',
              cleared ? 'border-2 border-[#DA3632] text-[#DA3632]' : 'border border-[#d9d9d9] text-[#b5b5b5]',
            ].join(' ')}
          >
            P
          </div>
        </div>

        <div className="mt-2 text-[12px] text-[#1e1e1e]">{points}p</div>

        {/* ??CLEAR 諭껋?: ?ㅻ뒛留?X, cleared硫??꾨? ?쒖떆 */}
        {cleared && (
          <div
            className={[
              'absolute left-1/2 -translate-x-1/2 mt-0',
              'top-[46px]',
              'px-2 py-[2px] rounded-md text-[11px] font-bold',
              isTodayCell ? 'bg-[#0e0e0e] text-white' : 'bg-[#1e1e1e] text-white',
            ].join(' ')}
          >
            CLEAR
          </div>
        )}
      </div>
    )
  }

  return (
    <div className="w-full">
      {toast && (
        <div className="mb-3 flex justify-center">
          <div className="px-3 py-2 bg-white border border-[#dcdcdc] text-[13px] font-semibold text-[#0e0e0e] shadow-sm">
            {toast}
          </div>
        </div>
      )}

      {(claimState.type === 'http_error' || claimState.type === 'network_error') && (
        <div className="mb-2 text-right text-[13px] text-red-600">
          Status error:{' '}
          {claimState.type === 'http_error' ? `http_error (${claimState.status})` : 'network_error'}
        </div>
      )}

      {/* ??14-Day Stamp Board */}
      <div className="border border-[#dcdcdc] bg-white p-5">
        <div className="flex items-center justify-between">
          <div className="text-[15px] font-semibold">14-Day Stamp Board</div>
          <div className="text-[13px] font-semibold text-[#1e1e1e]">Streak: {cyclePos || 0}</div>
        </div>

        {/* Desktop: 7 x 2 */}
        <div className="mt-4 hidden md:grid grid-cols-7 gap-3">
          {cells.map((c) => (
            <StampCell key={c.day} {...c} />
          ))}
        </div>

        {/* Mobile: 5 / 5 / 4 */}
        <div className="mt-4 md:hidden space-y-3">
          {mobileRows.map((row, idx) => (
            <div key={idx} className={['grid gap-3', idx === 2 ? 'grid-cols-4' : 'grid-cols-5'].join(' ')}>
              {row.map((c: any) => (
                <StampCell key={c.day} {...c} />
              ))}
            </div>
          ))}
        </div>
      </div>

      {/* ??My Reward */}
      <div className="mt-5 border border-[#dcdcdc] bg-white p-5">
        <div className="flex items-center justify-between gap-3">
          <div>
            <div className="text-[15px] font-medium">My Reward</div>
            <div className="mt-1 text-[13px] text-gray-700">
              {summaryText ?? 'Sign in to track your streak and points.'}
            </div>
          </div>

          <button
            onClick={onClaim}
            disabled={loading}
            className={[
              'h-10 px-4',
              'bg-[#DA3632] text-white',
              'text-[13px] font-semibold',
              'disabled:opacity-60 disabled:cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Checking?? : 'Claim today'}
          </button>
        </div>

        <p className="mt-3 text-[12px] text-gray-500 leading-relaxed">
          * Claim today is available after you ask at least 1 question on the Coach.
          <br />
          * If you click without signing in, you?셪l be asked to sign in.
        </p>
      </div>

      {/* ???덈궡/?먮윭 紐⑤떖 */}
      {modal.open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="w-full max-w-sm bg-white p-6 text-[#0e0e0e] border border-[#dcdcdc]">
            <h3 className="text-[14px] font-semibold">{modal.title}</h3>
            <p className="mt-2 text-[13px] text-gray-700 whitespace-pre-line">{modal.body}</p>

            <div className="mt-5 flex justify-end">
              <button
                onClick={() => setModal({ open: false, title: '', body: '' })}
                className="h-9 px-4 bg-[#1e1e1e] text-white text-[13px] font-semibold"
              >
                OK
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ??濡쒓렇???붽뎄 ?앹뾽 */}
      {showLoginModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="w-full max-w-sm bg-white p-6 text-center text-[#0e0e0e] border border-[#dcdcdc]">
            <h3 className="text-[13px] font-semibold text-[#1e1e1e]">Sign in required</h3>
            <p className="mt-2 text-[13px] text-gray-700">You need to sign in to use this feature.</p>

            <div className="mt-4 grid gap-2">
              <button
                onClick={loginGoogle}
                className="h-10 bg-[#1e1e1e] text-white text-[13px] font-semibold"
              >
                Sign in
              </button>
              <button
                onClick={() => setShowLoginModal(false)}
                className="h-10 border border-[#dcdcdc] text-[13px] font-medium text-[#1e1e1e]"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useCallback, useEffect, useMemo, useState } from 'react'
import Image from 'next/image'
import { useAuthUser, useSupabase } from '@/app/providers'

function stripTrailingSlash(s: string) {
  return s.replace(/\/$/, '')
}

function getSiteOrigin() {
  const envSite = (process.env.NEXT_PUBLIC_SITE_URL || '').trim()
  if (envSite) return stripTrailingSlash(envSite)
  if (typeof window !== 'undefined') return window.location.origin
  return ''
}

type StatusRes =
  | { ok: true; today: string; claimed_today: boolean; streak: number; board: boolean[] }
  | { ok: false; reason: string; error?: string }

const MSG_SUCCESS = "Today's reward has been granted."
const MSG_NO_QUESTION = 'Please ask at least one question in the AI Parenting Coach and then claim.'
const MSG_ALREADY = "You've already claimed today's reward."
const MSG_NEED_SIGNIN = 'Please sign in to claim today?셲 reward.'
const MSG_UNKNOWN = 'Something went wrong. Please try again.'

const REWARDS = [
  100, 100, 100, 100, 100, 100, // Day1-6
  300, // Day7
  100, 100, 100, 100, 100, 100, // Day8-13
  600, // Day14
]

// ??Indianbob colors
const INDIANBOB_RED = '#9F1D23'
const ACCENT_BLUE = '#3EB6F1'

// ??Stamp icons
const STAMP_BEFORE_SRC = '/reward/stamp-before.png'
const STAMP_AFTER_SRC = '/reward/stamp-after.png'

function IconWrap({ children, bg }: { children: React.ReactNode; bg: string }) {
  return (
    <div
      className="w-10 h-10 rounded-xl flex items-center justify-center border"
      style={{ backgroundColor: bg, borderColor: 'rgba(0,0,0,0.06)' }}
    >
      {children}
    </div>
  )
}

function SvgGift({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M20 7H4v5h16V7Z" stroke={color} strokeWidth="2" strokeLinejoin="round" />
      <path d="M12 7v14" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path
        d="M4 12v7a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-7"
        stroke={color}
        strokeWidth="2"
        strokeLinejoin="round"
      />
      <path
        d="M12 7H8.5a2.5 2.5 0 1 1 0-5C11 2 12 7 12 7Z"
        stroke={color}
        strokeWidth="2"
        strokeLinejoin="round"
      />
      <path
        d="M12 7h3.5a2.5 2.5 0 1 0 0-5C13 2 12 7 12 7Z"
        stroke={color}
        strokeWidth="2"
        strokeLinejoin="round"
      />
    </svg>
  )
}

function SvgList({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M8 6h13" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M8 12h13" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M8 18h13" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M3 6h.01M3 12h.01M3 18h.01" stroke={color} strokeWidth="3" strokeLinecap="round" />
    </svg>
  )
}

function SvgCalendar({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M7 3v3M17 3v3" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M4 8h16" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path
        d="M6 5h12a2 2 0 0 1 2 2v13a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2Z"
        stroke={color}
        strokeWidth="2"
        strokeLinejoin="round"
      />
    </svg>
  )
}

function SvgReset({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M21 12a9 9 0 1 1-3.2-6.9" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M21 3v6h-6" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  )
}

function SvgCoins({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M12 4c4.4 0 8 1.3 8 3s-3.6 3-8 3-8-1.3-8-3 3.6-3 8-3Z" stroke={color} strokeWidth="2" />
      <path d="M4 7v5c0 1.7 3.6 3 8 3s8-1.3 8-3V7" stroke={color} strokeWidth="2" />
      <path d="M4 12v5c0 1.7 3.6 3 8 3s8-1.3 8-3v-5" stroke={color} strokeWidth="2" />
    </svg>
  )
}

function SvgAlert({ color }: { color: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
      <path d="M12 9v5" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <path d="M12 17h.01" stroke={color} strokeWidth="3" strokeLinecap="round" />
      <path
        d="M10.3 3.6 2.7 18a2 2 0 0 0 1.8 3h15a2 2 0 0 0 1.8-3L13.7 3.6a2 2 0 0 0-3.4 0Z"
        stroke={color}
        strokeWidth="2"
        strokeLinejoin="round"
      />
    </svg>
  )
}

function Modal({
  open,
  title,
  message,
  onClose,
}: {
  open: boolean
  title: string
  message: string
  onClose: () => void
}) {
  if (!open) return null
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
      <div className="w-full max-w-sm bg-white border border-[#dcdcdc] p-6">
        <div className="text-[16px] font-extrabold text-[#1e1e1e]">{title}</div>
        <div className="mt-2 text-[14px] text-gray-700 whitespace-pre-wrap leading-relaxed">{message}</div>
        <div className="mt-5 flex justify-end">
          <button onClick={onClose} className="h-10 px-5 rounded-md bg-[#1e1e1e] text-white text-[14px] font-semibold">
            OK
          </button>
        </div>
      </div>
    </div>
  )
}

export default function RewardPage() {
  const supabase = useSupabase()
  const { user, loading: authLoading } = useAuthUser()

  const [loadingClaim, setLoadingClaim] = useState(false)
  const [status, setStatus] = useState<StatusRes | null>(null)
  const [loadingStatus, setLoadingStatus] = useState(false)

  const [modalOpen, setModalOpen] = useState(false)
  const [modalMsg, setModalMsg] = useState('')
  const [modalTitle, setModalTitle] = useState('')

  const openModal = useCallback((title: string, message: string) => {
    setModalTitle(title)
    setModalMsg(message)
    setModalOpen(true)
  }, [])

  const loginGoogle = useCallback(async () => {
    const base = getSiteOrigin()
    const redirectTo = `${base}/auth/callback?next=/reward`
    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo },
    })
  }, [supabase])

  const loadStatus = useCallback(async () => {
    if (!user) {
      setStatus(null)
      return
    }
    setLoadingStatus(true)
    try {
      const res = await fetch('/api/rewards/status', { method: 'GET' })
      const raw = await res.text()

      let json: any = {}
      try {
        json = raw ? JSON.parse(raw) : {}
      } catch {
        json = {}
      }

      if (!res.ok) {
        setStatus({ ok: false, reason: 'http_error', error: `HTTP ${res.status}\n${raw.slice(0, 800)}` })
        return
      }

      setStatus(json as StatusRes)
    } catch (e) {
      setStatus({ ok: false, reason: 'client_error', error: String(e) } as any)
    } finally {
      setLoadingStatus(false)
    }
  }, [user])

  useEffect(() => {
    void loadStatus()
  }, [loadStatus])

  function normalizeClaimResponse(json: any): { ok: boolean; reason?: string } {
    if (!json || typeof json !== 'object') return { ok: false, reason: 'bad_json' }

    if (typeof json.ok === 'boolean') {
      if (json.ok) return { ok: true }
      return { ok: false, reason: String(json.reason ?? 'unknown') }
    }

    if (typeof json.claimed === 'boolean') {
      if (json.claimed) return { ok: true }
      const r = String(json.reason ?? '')
      return { ok: false, reason: r || 'already_claimed' }
    }

    return { ok: false, reason: 'unknown_payload' }
  }

  const handleClaim = useCallback(async () => {
    if (!user) {
      openModal('Sign in required', MSG_NEED_SIGNIN)
      return
    }

    setLoadingClaim(true)
    try {
      const res = await fetch('/api/rewards/claim', { method: 'POST' })
      const raw = await res.text()

      let json: any = {}
      try {
        json = raw ? JSON.parse(raw) : {}
      } catch {
        json = {}
      }

      if (!res.ok) {
        openModal('Error', `${MSG_UNKNOWN}\n\nHTTP ${res.status}\n${raw.slice(0, 800)}`)
        return
      }

      const norm = normalizeClaimResponse(json)

      if (norm.ok) {
        openModal('Success', MSG_SUCCESS)
        window.dispatchEvent(new Event('points:refresh'))
        await loadStatus()
        return
      }

      if (norm.reason === 'no_question_today') {
        openModal('Action required', MSG_NO_QUESTION)
        return
      }
      if (norm.reason === 'already_claimed') {
        openModal('Already claimed', MSG_ALREADY)
        return
      }
      if (norm.reason === 'not_authenticated') {
        openModal('Sign in required', MSG_NEED_SIGNIN)
        return
      }

      openModal('Error', `${MSG_UNKNOWN}\n\nreason=${norm.reason}\n${raw.slice(0, 800)}`)
    } catch (e) {
      openModal('Error', `${MSG_UNKNOWN}\n\n${String(e)}`)
    } finally {
      setLoadingClaim(false)
    }
  }, [user, openModal, loadStatus])

  const claimedToday = status?.ok ? status.claimed_today : false
  const board = status?.ok ? status.board : Array.from({ length: 14 }, () => false)
  const streak = status?.ok ? status.streak : 0

  const claimButton = useMemo(() => {
    if (authLoading) {
      return (
        <button disabled className="rounded-md bg-gray-200 px-5 py-3 text-[15px] font-semibold text-gray-500">
          Loading??r
        </button>
      )
    }

    if (!user) {
      return (
        <button onClick={loginGoogle} className="rounded-md bg-[#1e1e1e] px-5 py-3 text-[15px] font-semibold text-white">
          Sign in with Google
        </button>
      )
    }

    return (
      <button
        onClick={handleClaim}
        disabled={loadingClaim}
        className="rounded-md px-5 py-3 text-[15px] font-semibold text-white disabled:opacity-60"
        style={{ backgroundColor: INDIANBOB_RED }}
      >
        {loadingClaim ? 'Claiming?? : 'Claim today'}
      </button>
    )
  }, [authLoading, user, loadingClaim, loginGoogle, handleClaim])

  // ???뱀뀡 ??댄?(Stamp Board? ?숈씪????濡??듭씪?섍린 ?꾪븳 怨듯넻 ?대옒??r
  const sectionTitleClass = 'text-[16px] md:text-[18px] font-semibold text-[#1e1e1e]'

  return (
    <main className="min-h-screen bg-white text-[#0e0e0e]">
      <div className="mx-auto max-w-5xl px-4 py-10">
        <Modal open={modalOpen} title={modalTitle} message={modalMsg} onClose={() => setModalOpen(false)} />

        <h1 className="text-[22px] font-medium leading-tight">Reward</h1>
        <p className="mt-3 text-[14px] text-[#b4b4b4]">Daily check-in rewards for asking 1 question on Coach.</p>

        <div className="mt-10 border-t border-[#eeeeee]">
          {/* ===================== 1) 14-Day Stamp Board ===================== */}
          <section className="py-10">
            <div className="flex items-center justify-between">
              <div className={sectionTitleClass}>14-Day Stamp Board</div>

              {user ? (
                <div className="text-[13px] md:text-[14px] text-gray-600">
                  {status?.ok ? (
                    <>
                      Streak: <span className="font-extrabold text-[#1e1e1e]">{streak}</span>
                      {loadingStatus ? <span className="ml-2">Loading??/span> : null}
                    </>
                  ) : (
                    <>
                      {loadingStatus ? (
                        <span>Loading??/span>
                      ) : (
                        <span className="text-red-600">Status error: {status?.reason}</span>
                      )}
                    </>
                  )}
                </div>
              ) : null}
            </div>

            <div className="mt-5 grid grid-cols-7 gap-2">
              {Array.from({ length: 14 }).map((_, i) => {
                const day = i + 1
                const filled = board[i]
                const filledCount = board.filter(Boolean).length

                return (
                  <div key={day} className="border border-[#eeeeee] bg-white text-center p-2 min-h-[84px]">
                    <div className="text-[11px] font-semibold text-[#1e1e1e]">Day {day}</div>

                    <div className="mt-2 flex items-center justify-center">
                      <div className="relative w-6 h-6">
                        <Image
                          src={filled ? STAMP_AFTER_SRC : STAMP_BEFORE_SRC}
                          alt={filled ? 'Mission completed' : 'Mission not started'}
                          fill
                          sizes="24px"
                          className={['object-contain', !user ? 'opacity-70' : 'opacity-100'].join(' ')}
                          priority={false}
                        />
                      </div>
                    </div>

                    <div className="mt-2 text-[11px] text-gray-700 font-semibold">{REWARDS[i]}p</div>

                    {claimedToday && filled && day === filledCount ? (
                      <div
                        className="mt-2 inline-flex items-center justify-center px-2 py-0.5 rounded text-[10px] font-extrabold text-white"
                        style={{ backgroundColor: '#1e1e1e' }}
                      >
                        CLEAR
                      </div>
                    ) : null}
                  </div>
                )
              })}
            </div>
          </section>

          {/* ===================== (?대룞) My Reward ===================== */}
          <section className="border-t border-[#eeeeee] py-10">
            {/* ????댄?: Stamp Board? ?숈씪???ш린/援듦린 */}
            <div className="flex items-center justify-between gap-3">
              <div>
                <div className={sectionTitleClass}>My Reward</div>
                <div className="mt-2 text-[14px] md:text-[15px] text-gray-700 leading-relaxed">
                Claim today is available after you ask at least 1 question on the Coach.
                </div>
              </div>

              {claimButton}
            </div>
          </section>

          {/* ===================== 2) Daily Check-in ===================== */}
          <section className="border-t border-[#eeeeee] py-10">
            {/* ????댄?: Stamp Board? ?숈씪???ш린/援듦린 */}
            <div className={sectionTitleClass}>Daily Check-in</div>
            <div className="mt-2 text-[14px] md:text-[15px] text-gray-700 leading-relaxed">
              Ask 1 question on Coach each day to earn points. Complete 14 days to finish the cycle, then it restarts from Day 1.
            </div>

            <div className="mt-5 grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="border border-[#eeeeee] p-5 bg-white">
                <div className="flex items-center gap-3">
                  <IconWrap bg="rgba(159,29,35,0.08)">
                    <SvgGift color={INDIANBOB_RED} />
                  </IconWrap>
                  <div className="text-[16px] md:text-[17px] font-extrabold text-[#1e1e1e]">Rewards</div>
                </div>

                <div className="mt-4 space-y-3">
                  <div className="flex items-start gap-3">
                    <div className="mt-0.5">
                      <SvgCalendar color={ACCENT_BLUE} />
                    </div>
                    <div className="text-[14px] md:text-[14px] text-gray-800 leading-relaxed">
                      <span className="font-semibold">Day 1??:</span>{' '}
                      <span className="font-extrabold" style={{ color: INDIANBOB_RED }}>
                        100p/day
                      </span>
                    </div>
                  </div>

                  <div className="flex items-start gap-3">
                    <div className="mt-0.5">
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden>
                        <path d="M12 5v14" stroke={ACCENT_BLUE} strokeWidth="2" strokeLinecap="round" />
                        <path d="M5 12h14" stroke={ACCENT_BLUE} strokeWidth="2" strokeLinecap="round" />
                      </svg>
                    </div>
                    <div className="text-[14px] md:text-[15px] text-gray-800 leading-relaxed">
                      <span className="font-semibold">Day 7:</span>{' '}
                      <span className="font-extrabold" style={{ color: INDIANBOB_RED }}>
                        300p
                      </span>
                    </div>
                  </div>

                  <div className="flex items-start gap-3">
                    <div className="mt-0.5">
                      <SvgCalendar color={ACCENT_BLUE} />
                    </div>
                    <div className="text-[14px] md:text-[15px] text-gray-800 leading-relaxed">
                      <span className="font-semibold">Day 8??3:</span>{' '}
                      <span className="font-extrabold" style={{ color: INDIANBOB_RED }}>
                        100p/day
                      </span>
                    </div>
                  </div>

                  <div className="flex items-center gap-3">
                    <div className="mt-0.5">
                      <SvgGift color={ACCENT_BLUE} />
                    </div>
                    <div className="text-[14px] md:text-[15px] text-gray-800 leading-relaxed">
                      <span className="font-semibold">Day 14:</span>{' '}
                      <span className="font-extrabold" style={{ color: INDIANBOB_RED }}>
                        600p
                      </span>
                      <span
                        className="ml-2 inline-flex items-center justify-center px-2 py-0.5 rounded-full text-[12px] font-extrabold"
