                              >
                                {tag}
                              </span>
                            ))}
                          </div>

                          <div className="text-sm text-white/70 mt-3">
                            ?쒖옉媛 {Math.round(it.base_price).toLocaleString()}??r
                          </div>
                        </div>
                      </Link>
                    )
                  })}
                </div>
              )}
            </section>

            {/* ??湲곗〈 TEAM(而ㅻ??덊떚) */}
            <section className="mt-10">
              <h2 className="text-xl font-semibold">COMMUNITY TEAMS</h2>

              {teams.length === 0 ? (
                <p className="text-gray-400 mt-3">?깅줉??TEAM???놁뒿?덈떎.</p>
