                    </Link>
                  )})}
                </div>
              )}
            </section>
          </>
        )}
      </div>
    </main>
  )
}

'use client'

import { useMemo, useState } from 'react'
import { useRouter } from 'next/navigation'

const INDIANBOB_RED = '#9F1D23'

type Props = { teamId: string }

function isValidEmail(v: string) {
  const s = v.trim()
  if (!s) return false
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s)
}

function Modal({
  open,
  title,
  message,
  email,
  setEmail,
  submitting,
  canSubmit,
  onClose,
  onSubmit,
}: {
  open: boolean
  title: string
  message: string
  email: string
  setEmail: (v: string) => void
  submitting: boolean
  canSubmit: boolean
  onClose: () => void
  onSubmit: () => void
}) {
  if (!open) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4">
      <div className="w-full max-w-md rounded-2xl bg-white p-6 shadow-lg">
        <div className="text-[16px] font-extrabold text-[#1e1e1e]">{title}</div>
        <div className="mt-2 text-[13px] leading-relaxed text-[#6b6b6b] whitespace-pre-wrap">{message}</div>

        <input
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="you@example.com"
          className="mt-4 w-full rounded-lg border border-[#e5e5e5] bg-[#f7fbff] px-4 py-3 text-[14px] outline-none focus:border-[#bcdcff]"
          autoFocus
          inputMode="email"
        />

        <div className="mt-4 flex gap-2 justify-end">
          <button
            onClick={onClose}
            disabled={submitting}
            className="h-10 rounded-lg px-4 text-[13px] font-semibold border border-[#e5e5e5] text-[#1e1e1e] disabled:opacity-50"
          >
            Cancel
          </button>

          <button
            onClick={onSubmit}
            disabled={submitting || !canSubmit}
            className="h-10 rounded-lg px-5 text-[13px] font-semibold text-white disabled:opacity-60"
            style={{ backgroundColor: INDIANBOB_RED }}
          >
            {submitting ? 'Submitting?? : 'Submit'}
          </button>
        </div>
      </div>
    </div>
  )
}

function AlertModal({
  open,
  title,
  message,
  onClose,
}: {
  open: boolean
  title: string
  message: string
  onClose: () => void
}) {
  if (!open) return null
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/40 px-4">
      <div className="w-full max-w-sm rounded-2xl bg-white p-6 shadow-lg border border-[#e5e5e5]">
        <div className="text-[15px] font-extrabold text-[#1e1e1e]">{title}</div>
        <div className="mt-2 text-[13px] text-[#6b6b6b] whitespace-pre-wrap leading-relaxed">{message}</div>
        <div className="mt-5 flex justify-end">
          <button onClick={onClose} className="h-10 rounded-lg bg-[#111] px-5 text-[13px] font-semibold text-white">
            OK
          </button>
        </div>
      </div>
    </div>
  )
}

export default function GiveawayEntryButtonClient({ teamId }: Props) {
  const router = useRouter()

  const [open, setOpen] = useState(false)
  const [email, setEmail] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const [alertOpen, setAlertOpen] = useState(false)
  const [alertTitle, setAlertTitle] = useState('Notice')
  const [alertMsg, setAlertMsg] = useState('')

  const entryTitle = 'Entry completed'
  const entryMsg =
    "Your entry has been received. If you win, we?셪l contact you by email.\nPlease enter the email address to notify."

  const showAlert = (title: string, msg: string) => {
    setAlertTitle(title)
    setAlertMsg(msg)
    setAlertOpen(true)
  }

  const canSubmit = useMemo(() => isValidEmail(email), [email])

  const onClickEnter = () => setOpen(true)

  const onClose = () => {
    if (submitting) return
    setOpen(false)
  }

  const onSubmit = async () => {
    if (!canSubmit) {
      showAlert('Invalid email', 'Please enter a valid email address.')
      return
    }

    setSubmitting(true)
    try {
      const res = await fetch('/api/giveaway/enter', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ teamId, email: email.trim().toLowerCase() }),
      })

      const json = await res.json().catch(() => null)

      if (!res.ok) {
        const msg = json?.message || json?.error || `Request failed (${res.status}). Please try again.`
        showAlert('Error', msg)
        return
      }

      if (json?.alreadyEntered) {
        showAlert('Already entered', 'You have already entered this giveaway.')
        setOpen(false)
        setEmail('')
        // ???レ옄/?뺣쪧 媛깆떊
        router.refresh()
        return
      }

      showAlert('Done', 'Your email has been saved. Thank you!')
      setOpen(false)
      setEmail('')

      // ???レ옄/?뺣쪧 媛깆떊 (?쒕쾭 而댄룷?뚰듃 ?щ젋??
      router.refresh()
    } catch (e: any) {
      showAlert('Network error', e?.message || 'Please try again.')
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <>
      <button
        type="button"
        onClick={onClickEnter}
        className="h-[44px] px-8 rounded-full text-white text-[14px] font-semibold"
        style={{ backgroundColor: INDIANBOB_RED }}
      >
        Enter for Free
      </button>

      <Modal
        open={open}
        title={entryTitle}
        message={entryMsg}
        email={email}
        setEmail={setEmail}
        submitting={submitting}
        canSubmit={canSubmit}
        onClose={onClose}
        onSubmit={onSubmit}
      />

      <AlertModal open={alertOpen} title={alertTitle} message={alertMsg} onClose={() => setAlertOpen(false)} />
    </>
  )
}

'use client'

import { useMemo, useState } from 'react'
import { useRouter } from 'next/navigation'
import { useAuthUser, useSupabase } from '@/app/providers'

type Props = { teamId: string }

// ???대깽???ID (Korean Daily Care Essential)
const GIVEAWAY_TEAM_ID = 'e2c8be1a-31df-4554-890c-e2dde44c5aec'

function isValidEmail(email: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)
}

export default function JoinButtonClient({ teamId }: Props) {
  const supabase = useSupabase()
  const { user, loading } = useAuthUser()
  const router = useRouter()

  const isGiveaway = teamId === GIVEAWAY_TEAM_ID

  const [submitting, setSubmitting] = useState(false)

  // 湲곗〈 紐⑤떖(濡쒓렇???먮윭/?꾨즺) - ?ъ궗??r
  const [open, setOpen] = useState(false)
  const [modalTitle, setModalTitle] = useState('Sign in required')
  const [modalMessage, setModalMessage] = useState('You must be signed in to join.')
  const [modalAction, setModalAction] = useState<'close' | 'google_login'>('close')

  // ???대찓???낅젰 紐⑤떖 (giveaway ?꾩슜)
  const [emailModalOpen, setEmailModalOpen] = useState(false)
  const [emailValue, setEmailValue] = useState('')
  const [emailError, setEmailError] = useState('')

  const showModal = (title: string, message: string, action: 'close' | 'google_login' = 'close') => {
    setModalTitle(title)
    setModalMessage(message)
    setModalAction(action)
    setOpen(true)
  }

  const closeModal = () => setOpen(false)

  const startGoogleLogin = async () => {
    setOpen(false)

    const redirectTo = typeof window !== 'undefined' ? window.location.href : undefined

    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo,
        queryParams: { prompt: 'select_account' },
      },
    })

    if (error) {
      console.error('[signInWithOAuth] error:', error)
      showModal('Error', String((error as any)?.message ?? 'Login failed.'), 'close')
    }
  }

  const onModalOk = async () => {
    if (modalAction === 'google_login') {
      await startGoogleLogin()
      return
    }
    closeModal()
  }

  // ??team_members insert (Joined N 利앷???
  const ensureJoined = async () => {
    if (!teamId) throw new Error('Missing teamId')
    if (!user) throw new Error('Missing user')

    // ?좎? ?대찓???덉쟾 ?뺣낫 (湲곗〈 濡쒖쭅 ?좎?)
    const { data: userRes, error: userErr } = await supabase.auth.getUser()
    if (userErr) console.error('[auth.getUser] error:', userErr)

    const email = userRes?.user?.email ?? null

    const { error: insErr } = await supabase.from('team_members').insert([
      {
        team_id: teamId,
        user_id: user.id,
        email,
      },
    ])

    if (insErr) {
      const msg = String((insErr as any)?.message ?? '')
      const code = (insErr as any)?.code

      // 以묐났 join?대㈃ OK 痍④툒
      if (code === '23505' || msg.toLowerCase().includes('duplicate')) {
        return { alreadyJoined: true }
      }

      throw new Error(msg || 'Insert failed.')
    }

    return { alreadyJoined: false }
  }

  // ??giveaway ?대찓?????r
  const saveGiveawayEmail = async (email: string) => {
    const res = await fetch('/api/giveaway/enter', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ teamId, email }),
      cache: 'no-store',
    })

    const json = await res.json().catch(() => null)

    if (!res.ok) {
      const err = json?.error || 'request_failed'
      const msg = json?.message || ''
      throw new Error(msg ? `${err}: ${msg}` : err)
    }

    if (!json?.ok) {
      throw new Error(json?.error || 'request_failed')
    }
  }

  // ??giveaway 踰꾪듉 ?대┃ ???대찓???낅젰 ?앹뾽
  const openEmailModal = async () => {
    if (!user) {
      showModal('Sign in required', 'You must be signed in to enter for free.', 'google_login')
      return
    }

    // 湲곕낯媛? 濡쒓렇???대찓???덉쑝硫?
    let defaultEmail = ''
    try {
      const { data } = await supabase.auth.getUser()
      defaultEmail = data?.user?.email ? String(data.user.email) : ''
    } catch {
      defaultEmail = ''
    }

    setEmailValue(defaultEmail)
    setEmailError('')
    setEmailModalOpen(true)
  }

  const closeEmailModal = () => {
    setEmailModalOpen(false)
    setEmailError('')
  }

  // ??giveaway ?쒖텧 (join + email ???
  const submitGiveaway = async () => {
    const email = (emailValue || '').trim()

    if (!email || !isValidEmail(email)) {
      setEmailError('Please enter a valid email address.')
      return
    }

    if (!user) {
      closeEmailModal()
      showModal('Sign in required', 'You must be signed in to enter for free.', 'google_login')
      return
    }

    setSubmitting(true)
    setEmailError('')

    try {
      // 1) Joined N 移댁슫?몄슜
      await ensureJoined()

      // 2) giveaway_entries ???r
      await saveGiveawayEmail(email)

      setSubmitting(false)
      setEmailModalOpen(false)
      router.refresh()

      showModal(
        'Entry completed',
        'Your entry has been submitted. If you win, we?셪l contact you at the email address you provided.',
        'close'
      )
    } catch (e: any) {
      console.error('[giveaway submit] error:', e)
      setSubmitting(false)
      setEmailError(String(e?.message ?? e ?? 'Failed to submit'))
    }
  }

  // ???쇰컲 ?곹뭹 join (湲곗〈)
  const joinNormal = async () => {
    if (!teamId) return

    if (!user) {
      showModal('Sign in required', 'You must be signed in to join.', 'google_login')
      return
    }

    setSubmitting(true)

    try {
      await ensureJoined()

      setSubmitting(false)
      router.refresh()

      showModal(
        'Thanks for joining!',
        'Thank you for joining. You won?셳 be charged right now, and nothing will be shipped yet. When the official sale begins, we?셪l notify you by email.',
        'close'
      )
    } catch (e: any) {
      console.error('[join] unexpected error:', e)
      setSubmitting(false)
      showModal('Error', String(e?.message ?? e ?? 'Failed to join'), 'close')
    }
  }

  const onClickMain = async () => {
    if (loading || submitting) return

    if (isGiveaway) {
      await openEmailModal()
      return
    }

    await joinNormal()
  }

  const buttonLabel = useMemo(() => {
    if (submitting) return isGiveaway ? 'Submitting?? : 'Joining??
    return isGiveaway ? 'Enter for Free' : 'Join now'
  }, [submitting, isGiveaway])

  return (
    <>
      <button
        onClick={onClickMain}
        disabled={loading || submitting}
        className="rounded-full bg-[#0e0e0e] px-8 py-3 text-[15px] font-semibold text-white hover:opacity-90 disabled:opacity-50"
      >
        {buttonLabel}
      </button>

      {/* ??Giveaway Email Modal */}
      {emailModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4" role="dialog" aria-modal="true">
          <div className="absolute inset-0 bg-black/50" onClick={closeEmailModal} />
          <div className="relative w-full max-w-sm rounded-2xl bg-white shadow-xl">
            <div className="px-5 pt-5">
              <h3 className="text-[16px] font-semibold text-[#0e0e0e]">Entry completed</h3>
              <p className="mt-2 text-[14px] leading-6 text-[#444]">
                Your entry will be submitted for free. If you win, please provide the email address where we should contact you.
              </p>

              <div className="mt-4">
                <label className="block text-[13px] font-semibold text-[#111]">Email</label>
                <input
                  value={emailValue}
                  onChange={(e) => setEmailValue(e.target.value)}
                  placeholder="name@example.com"
                  className="mt-2 w-full rounded-xl border border-[#ddd] bg-white px-3 py-2 text-[14px] outline-none focus:border-[#0e0e0e]"
                />
                {emailError ? <p className="mt-2 text-[12px] font-semibold text-red-600">{emailError}</p> : null}
              </div>
            </div>

            <div className="mt-5 flex items-center justify-end gap-2 border-t border-[#eee] px-5 py-3">
              <button
                type="button"
                onClick={closeEmailModal}
                disabled={submitting}
                className="h-9 rounded-lg border border-[#ddd] bg-white px-3 text-[14px] font-semibold text-[#111] hover:bg-[#f7f7f7] disabled:opacity-50"
              >
                Cancel
              </button>

              <button
                type="button"
                onClick={submitGiveaway}
                disabled={submitting}
                className="h-9 rounded-lg bg-[#0e0e0e] px-4 text-[14px] font-semibold text-white hover:opacity-90 disabled:opacity-50"
              >
                {submitting ? 'Submitting?? : 'Submit'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ??湲곗〈 Modal (濡쒓렇???먮윭/?꾨즺) */}
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4" role="dialog" aria-modal="true">
          <div className="absolute inset-0 bg-black/50" onClick={closeModal} />
          <div className="relative w-full max-w-sm rounded-2xl bg-white shadow-xl">
            <div className="px-5 pt-5">
              <h3 className="text-[16px] font-semibold text-[#0e0e0e]">{modalTitle}</h3>
              <p className="mt-2 text-[14px] leading-6 text-[#444]">{modalMessage}</p>
            </div>

            <div className="mt-5 flex items-center justify-end gap-2 border-t border-[#eee] px-5 py-3">
              <button
                type="button"
                onClick={onModalOk}
                className="h-9 rounded-lg border border-[#ddd] bg-white px-3 text-[14px] font-semibold text-[#111] hover:bg-[#f7f7f7]"
              >
                OK
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}

'use client'

import Link from 'next/link'
import { useEffect, useMemo, useState } from 'react'
import { useParams } from 'next/navigation'
import { useAuthUser, useSupabase } from '@/app/providers'
import type { User } from '@supabase/supabase-js'

type Activity = {
  id: string
  team_id: string
  title: string
  description: string | null
  starts_at: string | null
  ends_at: string | null
  created_at: string
}

type Participant = {
  id: string
  activity_id: string
  user_id: string
  nickname: string | null
  created_at: string
}

function stripTrailingSlash(s: string) {
  return s.replace(/\/$/, '')
}

function getSiteOrigin() {
  const envSite = (process.env.NEXT_PUBLIC_SITE_URL || '').trim()
  if (envSite) return stripTrailingSlash(envSite)
  if (typeof window !== 'undefined') return window.location.origin
  return ''
}

function getUserLabel(user: User) {
  const md = (user.user_metadata ?? {}) as Record<string, any>
  return (
    md.full_name ||
    md.name ||
    (user.email ? String(user.email).split('@')[0] : null) ||
    (user.id ? String(user.id).slice(0, 8) : 'user')
  )
}

export default function ActivityDetailPage() {
  const supabase = useSupabase()
  const { user, loading: authLoading } = useAuthUser()
  const params = useParams()

  // ??params ?덉쟾 ?뚯떛 (以묐났 ?좎뼵 湲덉?)
  const teamId = useMemo(() => {
    const v = (params as any)?.teamId
    return typeof v === 'string' ? v : ''
  }, [params])

  const activityId = useMemo(() => {
    const v = (params as any)?.activityId
    return typeof v === 'string' ? v : ''
  }, [params])

  const [activity, setActivity] = useState<Activity | null>(null)
  const [participants, setParticipants] = useState<Participant[]>([])
  const [loading, setLoading] = useState(true)
  const [joining, setJoining] = useState(false)
  const [showLoginModal, setShowLoginModal] = useState(false)

  const alreadyJoined = useMemo(() => {
    if (!user) return false
    return participants.some((p) => p.user_id === user.id)
  }, [participants, user])

  const fetchAll = async () => {
    setLoading(true)

    const actRes = await supabase
      .from('team_activities')
      .select('id, team_id, title, description, starts_at, ends_at, created_at')
      .eq('id', activityId)
      .maybeSingle()

    const pRes = await supabase
      .from('activity_participants')
      .select('id, activity_id, user_id, nickname, created_at')
      .eq('activity_id', activityId)
      .order('created_at', { ascending: false })

    if (actRes.error) {
      console.error('[team_activities] error:', actRes.error)
      setActivity(null)
    } else {
      setActivity((actRes.data ?? null) as Activity | null)
    }

    if (pRes.error) {
      console.error('[activity_participants] error:', pRes.error)
      setParticipants([])
    } else {
      setParticipants((pRes.data ?? []) as Participant[])
    }

    setLoading(false)
  }

  useEffect(() => {
    if (!activityId) return
    fetchAll()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activityId])

  const loginGoogle = async () => {
    const base = getSiteOrigin()
    const redirectTo = `${base}/auth/callback?next=/team/${teamId}/activities/${activityId}`

    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo },
    })
  }

  const join = async () => {
    if (!user) {
      setShowLoginModal(true)
      return
    }
    if (!activityId) return
    if (alreadyJoined) return

    setJoining(true)
    const nickname = String(getUserLabel(user))

    const { error } = await supabase.from('activity_participants').insert([
      {
