                            <img src={cover} alt={name} className="w-full h-full object-cover" loading="lazy" />
                          ) : null}
                        </div>
                      </div>

                      {/* ???띿뒪??*/}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between gap-4">
                          <h2 className="text-[22px] font-semibold leading-tight truncate">{name}</h2>
                          <div className="shrink-0">
                            <JoinedPill count={joined} labelTmpl={t.joined} />
                          </div>
                        </div>

                        {purpose ? (
                          <p className="mt-3 text-[15px] text-[#7a7a7a] leading-relaxed line-clamp-3">
                            {purpose}
                          </p>
                        ) : null}

                        {(tag1 || tag2) ? (
                          <div className="mt-4 flex flex-wrap gap-2">
                            {tag1 ? <TagPill label={tag1} /> : null}
                            {tag2 ? <TagPill label={tag2} /> : null}
                          </div>
                        ) : null}
                      </div>
                    </div>
                  </Link>
                </li>
              )
            })}
          </ul>
        )}
      </div>
    </main>
  )
}

'use client'

import { useState, useEffect } from 'react'

export type I18nValues = {
  en: string
  ko: string
  id: string
  ms: string
  th: string
}

type Props = {
  label: string
  baseString: string | null | undefined
  i18nData: any // from DB row
  isTextArea?: boolean
  onChange: (enValue: string, translatedJsonb: I18nValues) => void
  disabled?: boolean
  maxLengthHint?: string
}

export default function TranslationInput({
  label,
  baseString,
  i18nData,
  isTextArea = false,
  onChange,
  disabled = false,
  maxLengthHint,
}: Props) {
  const [isOpen, setIsOpen] = useState(false)
  const [translating, setTranslating] = useState(false)
  const [err, setErr] = useState('')

  const [vals, setVals] = useState<I18nValues>({
    en: '',
    ko: '',
    id: '',
    ms: '',
    th: '',
  })

  // ??Legacy Row Seeding & Init
  // If no i18n data exists, we seed the EN value from the baseString
  useEffect(() => {
    setVals({
      en: typeof i18nData?.en === 'string' ? i18nData.en : (baseString ?? ''),
      ko: typeof i18nData?.ko === 'string' ? i18nData.ko : '',
      id: typeof i18nData?.id === 'string' ? i18nData.id : '',
      ms: typeof i18nData?.ms === 'string' ? i18nData.ms : '',
      th: typeof i18nData?.th === 'string' ? i18nData.th : '',
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [baseString, i18nData])

  const notifyChange = (newVals: I18nValues) => {
    // Sync EN to the base string exactly as requested by user rule #4
    onChange(newVals.en, newVals)
  }

  const handleUpdate = (lang: keyof I18nValues, val: string) => {
    const obj = { ...vals, [lang]: val }
    setVals(obj)
    notifyChange(obj)
  }

  const handleAutoTranslate = async () => {
    const sourceText = vals.en.trim()
    if (!sourceText) return

    setTranslating(true)
    setErr('')

    try {
      const res = await fetch('/api/admin/translate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: sourceText }),
      })

      const data = await res.json()

      if (!res.ok) {
        throw new Error(data.error || data.details || 'Translation failed')
      }

      // ??Overwrite ID, MS, TH with API defaults
      const merged = { ...vals, id: data.id, ms: data.ms, th: data.th }
      setVals(merged)
      notifyChange(merged)
      setIsOpen(true) // Open to show new translations

    } catch (e: any) {
      setErr(e.message)
    } finally {
      setTranslating(false)
    }
  }

  const enIsEmpty = vals.en.trim().length === 0
  const isTooLongWarning = vals.en.length > 4000

  const InputFrame = isTextArea ? 'textarea' : 'input'
  const inputProps = isTextArea ? { className: 'w-full p-2 h-32 bg-gray-800 text-white rounded outline-none border border-transparent focus:border-blue-500 disabled:opacity-60' } : { className: 'w-full p-2 bg-gray-800 text-white rounded outline-none border border-transparent focus:border-blue-500 disabled:opacity-60' }

  return (
    <div className="mb-4 bg-[#2a2a2a] border border-[#444] p-4 rounded-lg">
      <div className="flex justify-between items-center mb-2">
        <label className="text-sm font-semibold text-gray-200">{label}</label>
        <button
          type="button"
          onClick={handleAutoTranslate}
          disabled={disabled || enIsEmpty || translating}
          className="px-3 py-1.5 bg-[#9F1D23] text-white text-xs font-semibold rounded hover:bg-red-700 disabled:opacity-40 disabled:cursor-not-allowed flex items-center gap-1 transition-colors"
        >
          {translating ? '??Translating...' : '?뙉 Auto Translate from EN'}
        </button>
      </div>

      {maxLengthHint && <p className="text-xs text-yellow-400 mb-2">{maxLengthHint}</p>}
      {err && <p className="text-xs text-red-400 mb-2">{err}</p>}
      {isTooLongWarning && <p className="text-xs text-orange-400 mb-2">Warning: Source text is very long. Auto-translate might fail if it exceeds limits, and Markdown structures require careful review.</p>}

      {/* Main English Source */}
      <div className="mb-2">
        <div className="text-xs text-gray-400 mb-1 flex items-center gap-1 font-mono">
          <span className="bg-blue-900/50 text-blue-300 px-1.5 rounded">EN</span> English (Base Source)
        </div>
        <InputFrame
          {...inputProps}
          value={vals.en}
          onChange={(e) => handleUpdate('en', e.target.value)}
          disabled={disabled}
          placeholder="English content..."
        />
      </div>

      <div className="mb-2">
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          className="text-sm text-gray-400 hover:text-white flex items-center gap-1 transition-colors"
        >
          {isOpen ? '??Hide localized versions' : '??Show localized versions (KO, ID, MS, TH)'}
        </button>
      </div>

      {/* Expandable Regional Inputs */}
      {isOpen && (
        <div className="space-y-3 mt-4 border-t border-[#444] pt-4 grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-3">

          <div className="md:col-span-2">
            <div className="text-xs text-gray-400 mb-1 flex items-center gap-1 font-mono">
              <span className="bg-green-900/50 text-green-300 px-1.5 rounded">KO</span> Korean (Manual)
            </div>
            <InputFrame
              {...inputProps}
              value={vals.ko}
              onChange={(e) => handleUpdate('ko', e.target.value)}
              disabled={disabled}
              placeholder="Korean content..."
            />
          </div>

          <div>
            <div className="text-xs text-gray-400 mb-1 flex items-center gap-1 font-mono">
              <span className="bg-purple-900/50 text-purple-300 px-1.5 rounded">ID</span> Indonesian
            </div>
            <InputFrame
              {...inputProps}
              value={vals.id}
              onChange={(e) => handleUpdate('id', e.target.value)}
              disabled={disabled}
              placeholder="Indonesian content..."
            />
          </div>

          <div>
            <div className="text-xs text-gray-400 mb-1 flex items-center gap-1 font-mono">
              <span className="bg-teal-900/50 text-teal-300 px-1.5 rounded">MS</span> Malay
            </div>
            <InputFrame
              {...inputProps}
              value={vals.ms}
              onChange={(e) => handleUpdate('ms', e.target.value)}
              disabled={disabled}
              placeholder="Malay content..."
            />
          </div>

          <div className="md:col-span-2">
            <div className="text-xs text-gray-400 mb-1 flex items-center gap-1 font-mono">
              <span className="bg-orange-900/50 text-orange-300 px-1.5 rounded">TH</span> Thai
            </div>
            <InputFrame
              {...inputProps}
              value={vals.th}
              onChange={(e) => handleUpdate('th', e.target.value)}
              disabled={disabled}
              placeholder="Thai content..."
            />
          </div>

        </div>
      )}
    </div>
  )
}

// src/components/chat/ChatBox.tsx
'use client'

import { useCallback, useEffect, useRef, useState } from 'react'
import ReactMarkdown from 'react-markdown'
import { useAuthUser } from '@/app/providers'
import { useTranslation } from '@/i18n/I18nProvider'

type ChatBoxProps = { systemPrompt?: string; initialPrefill?: string }
type ChatRole = 'user' | 'assistant'

type ChatMessage = {
  id: string
  role: ChatRole
  content: string
  createdAt: number
}

type ApiChatOk = {
  answer?: string
  requestId?: string
  sessionId?: string
  insertOk?: boolean
  insertError?: string | null
}
type ApiChatErr = { error?: string; requestId?: string; message?: string; body?: string; status?: number }

function uuid() {
  if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) return crypto.randomUUID()
  return `id_${Date.now()}_${Math.random().toString(16).slice(2)}`
}

// ??鍮꾨줈洹몄씤 ?좎????덉젙?곸쑝濡??앸퀎?섍린 ?꾪븳 localStorage sessionId
const SESSION_KEY = 'cc_session_id'
function getOrCreateSessionId() {
  if (typeof window === 'undefined') return uuid()
  try {
    const existing = window.localStorage.getItem(SESSION_KEY)
    if (existing && existing.trim()) return existing.trim()
    const created = uuid()
    window.localStorage.setItem(SESSION_KEY, created)
    return created
  } catch {
    return uuid()
  }
}

/* -----------------------------------------
 * ??"?쇰꺼" 湲곕컲 媛뺤젣 異쒕젰 紐⑤뱶 (K_MOM_TAG ?쒓굅)
 * ---------------------------------------- */
const K_MOM_USER_LABEL = '?뮎 Korean Moms??Favorite Picks'

function normalizeForMatch(s: string) {
  return (s ?? '')
    .trim()
    .replace(/[?쇺?/g, "'")
    .replace(/[?쒋?/g, '"')
    .replace(/\s+/g, ' ')
    .toLowerCase()
}

function isKMomLabel(text: string) {
  const n = normalizeForMatch(text).replace(/^\p{Extended_Pictographic}\s*/u, '').trim()
  const target = normalizeForMatch(K_MOM_USER_LABEL).replace(/^\p{Extended_Pictographic}\s*/u, '').trim()
  return n === target
}

// ???덇? 以 臾멸뎄 "??湲?먮룄 鍮좎?吏 ?딄쾶" 洹몃?濡?r
const K_MOM_FIXED_ANSWER = `Hello?봊'm your AI Parenting Coach.

Let me share a few things that many Korean moms genuinely love.
It?셲 not just about what?셲 trending ??it means more to understand why they choose them.

1截뤴깵 Mommy & Child Beauty Essentials

In Korea, many families are moving away from strictly separate ?쐊ids-only??products.
Instead, there is a growing preference for gentle, clean beauty items that mothers and children can safely use together.

Cushion-style sunscreen compacts make it easier for children to apply sunscreen on their own, while water-washable play cosmetics combine safety with a touch of fun.

More than the product itself, many parents value the shared experience of daily routines done together.

2截뤴깵 Play-Based Learning Tools

Rather than focusing heavily on memorization, Korean early education increasingly emphasizes tools that stimulate thinking through play.

Magnetic blocks paired with structured activity sheets are especially popular.
Instead of simply stacking pieces, children are guided to recreate shapes or solve simple building challenges, naturally strengthening spatial awareness and problem-solving skills.

Talking pen systems are also widely used. By touching the pages of compatible books, children can hear stories and pronunciation, making language exposure feel interactive and self-directed.

It feels less like formal studying ??and more like ?쐔hinking through play.??r

3截뤴깵 Korean Postpartum Care Starter Kit

In Korea, postpartum recovery is treated as an essential stage of care.
This starter kit focuses on:

Maintaining warmth

Gentle, steady daily recovery routines

Practical self-care that can be done at home

It is not about intensive treatment, but about creating a calm and supportive recovery environment.

4截뤴깵 K-Kids Silicone Tableware Set

Designed to support independent eating, this set emphasizes suction stability, food-grade silicone safety, and easy cleaning.

Korean parents often prioritize both safe materials and reducing mealtime stress.
It is a practical choice that balances functionality with clean, modern design.

If you would like to explore more trending parenting items from Korea,
?몛 Visit the TEAM menu.

You can discover carefully selected, high-quality products that many Korean families already choose ??offered at reasonable community-driven prices.`

export default function ChatBox({ systemPrompt, initialPrefill }: ChatBoxProps) {
  // ??user??"?덉쑝硫??곌퀬, ?놁뼱??OK"
  const { user } = useAuthUser()
  const t = useTranslation('coach')

  const [input, setInput] = useState('')
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [loading, setLoading] = useState(false)
  const [dots, setDots] = useState(0)

  const [error, setError] = useState('')
  const [sessionId, setSessionId] = useState('')

  const endRef = useRef<HTMLDivElement | null>(null)
  const chatBarRef = useRef<HTMLDivElement | null>(null)

  const didMountRef = useRef(false)
  const prefillFiredRef = useRef(false)
  const prevMsgLenRef = useRef(0)

  useEffect(() => {
    setSessionId(getOrCreateSessionId())
  }, [])

  useEffect(() => {
    if (!loading) {
      setDots(0)
      return
    }
    const id = setInterval(() => setDots((d) => (d + 1) % 4), 400)
    return () => clearInterval(id)
  }, [loading])

  useEffect(() => {
    const el = chatBarRef.current
    if (!el) return

    const set = () => {
      const h = el.getBoundingClientRect().height
      document.documentElement.style.setProperty('--chatbar-h', `${Math.ceil(h)}px`)
    }

    set()

    const ro = new ResizeObserver(() => set())
    ro.observe(el)

    window.addEventListener('resize', set)
    window.addEventListener('orientationchange', set)

    return () => {
      ro.disconnect()
      window.removeEventListener('resize', set)
      window.removeEventListener('orientationchange', set)
    }
  }, [])

  useEffect(() => {
    if (!didMountRef.current) {
      didMountRef.current = true
      prevMsgLenRef.current = messages.length
      return
    }

    const prevLen = prevMsgLenRef.current
    const nowLen = messages.length
    prevMsgLenRef.current = nowLen

    const shouldScroll = nowLen > prevLen || loading
    if (!shouldScroll) return

    endRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' })
  }, [messages.length, loading])

  const push = useCallback((role: ChatRole, content: string) => {
    const id = uuid()
    setMessages((prev) => [...prev, { id, role, content, createdAt: Date.now() }])
    return id
  }, [])

  const updateMessage = useCallback((id: string, content: string) => {
    setMessages((prev) => prev.map((m) => (m.id === id ? { ...m, content } : m)))
  }, [])

  function sleep(ms: number) {
    return new Promise((r) => setTimeout(r, ms))
  }

  const typewriterAppend = useCallback(
    async (messageId: string, fullText: string, opts?: { cps?: number; chunk?: number }) => {
      const cps = Math.max(10, opts?.cps ?? 45)
      const chunk = Math.max(1, opts?.chunk ?? 2)
      const delay = Math.max(8, Math.floor((1000 / cps) * chunk))

      let i = 0
      while (i < fullText.length) {
        i += chunk
        const next = fullText.slice(0, i)
        updateMessage(messageId, next)
        await sleep(delay)
      }
    },
    [updateMessage]
  )


  async function safeJsonParse<T>(raw: string): Promise<T | null> {
    try {
      return raw ? (JSON.parse(raw) as T) : null
    } catch {
      return null
    }
  }

  const ask = useCallback(
    async (override?: string) => {
      const q = (override ?? input).trim()
      if (!q) return

      const sid = sessionId || getOrCreateSessionId()

      // ???쇰꺼 媛뺤젣 紐⑤뱶: Thinking ????댄븨?쇰줈 異쒕젰 (?쒕쾭 ?몄텧 ?놁씠)
      if (isKMomLabel(q)) {
        push('user', K_MOM_USER_LABEL)
        setInput('')
        setError('')

        setLoading(true)
        await sleep(650)
        setLoading(false)

        const mid = push('assistant', '')
        void typewriterAppend(mid, K_MOM_FIXED_ANSWER, { cps: 75, chunk: 3 })
        return
      }

      push('user', q)
      setInput('')
      setLoading(true)
      setError('')

      try {
        const res = await fetch('/api/chat', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            system: systemPrompt ?? '',
            question: q,
            sessionId: sid,
          }),
          cache: 'no-store',
        })

        const raw = await res.text()

        if (!res.ok) {
          const errJson = await safeJsonParse<ApiChatErr>(raw)
          const rid = errJson?.requestId ? ` (requestId: ${errJson.requestId})` : ''
          const core = `Error ${res.status}${rid}\n\n${errJson?.error || errJson?.message || 'api/chat failed'}`
          setError(core)
          push('assistant', core)
          return
        }

        const okJson = await safeJsonParse<ApiChatOk>(raw)
        const answer = (okJson?.answer || '').trim()

        // ???쒕쾭媛 ?몄뀡ID瑜??덈줈 ?대젮二쇰㈃ 濡쒖뺄?먮룄 諛섏쁺
        if (okJson?.sessionId && okJson.sessionId !== sid) {
          try {
            window.localStorage.setItem(SESSION_KEY, okJson.sessionId)
            setSessionId(okJson.sessionId)
          } catch {}
        }

        if (okJson?.insertOk === false) {
          console.warn('[chat_logs insert failed]', {
            requestId: okJson?.requestId,
            sessionId: okJson?.sessionId ?? sid,
            userId: user?.id ?? null,
            insertError: okJson?.insertError ?? null,
          })
        }

        if (!answer) {
          const rid = okJson?.requestId ? ` (requestId: ${okJson.requestId})` : ''
          const msg = `${t('chat_error_empty')}${rid}`
          setError(msg)
          push('assistant', msg)
          return
        }

        push('assistant', answer)
      } catch {
        const msg = t('chat_error_delayed')
        setError(msg)
        push('assistant', msg)
      } finally {
        setLoading(false)
      }
    },
    [input, sessionId, push, systemPrompt, user?.id, typewriterAppend]
  )

  // ??Auto-Submit Prefill Once
  useEffect(() => {
    if (initialPrefill && !prefillFiredRef.current && initialPrefill.trim() !== '') {
      prefillFiredRef.current = true
      
      // Auto trigger the ask function. Wait a tiny bit for UI to settle.
      setTimeout(() => {
        ask(initialPrefill)
        
        // Clean up the URL to prevent refresh double submits
        try {
          const url = new URL(window.location.href)
          url.searchParams.delete('prefill')
          window.history.replaceState({}, '', url.toString())
        } catch {}
      }, 300)
    }
  }, [initialPrefill, ask])

  // ???꾨━???ㅼ썙???대┃ ?대깽?? 濡쒓렇???놁씠??利됱떆 吏덈Ц ?ㅽ뻾
  useEffect(() => {
    const handler = (e: Event) => {
      const text = (e as CustomEvent<string>).detail
      const q = (text ?? '').trim()
      if (!q) return

      setInput(q)
      if (loading) return

      void ask(q)
    }

    window.addEventListener('coach:setMessage', handler as EventListener)
    return () => window.removeEventListener('coach:setMessage', handler as EventListener)
  }, [loading, ask])

  return (
    <div className="w-full">
      <div className="space-y-3 pb-[calc(var(--chatbar-h,96px)+16px)]">
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div
              className={[
                'max-w-[80%] rounded-xl px-4 py-3',
                'text-[15px] leading-relaxed',
                m.role === 'user'
                  ? 'bg-[#f0f1f6] text-[#0e0e0e] font-bold'
                  : 'bg-white border border-[#dcdcdc] text-[#0e0e0e] font-medium',
              ].join(' ')}
            >
              {m.role === 'assistant' ? (
                <div className="prose prose-sm max-w-none">
                  <ReactMarkdown
                    components={{
                      p: ({ children }) => <p className="my-2 whitespace-pre-wrap">{children}</p>,
                      h1: ({ children }) => <h1 className="mt-3 mb-2 text-[16px] font-semibold">{children}</h1>,
                      h2: ({ children }) => <h2 className="mt-3 mb-2 text-[16px] font-semibold">{children}</h2>,
                      h3: ({ children }) => <h3 className="mt-3 mb-2 text-[15px] font-semibold">{children}</h3>,
                      h4: ({ children }) => <h4 className="mt-3 mb-2 text-[15px] font-semibold">{children}</h4>,
                      ul: ({ children }) => <ul className="my-2 pl-5 list-disc">{children}</ul>,
                      ol: ({ children }) => <ol className="my-2 pl-5 list-decimal">{children}</ol>,
                      li: ({ children }) => <li className="my-1">{children}</li>,
                    }}
                  >
                    {m.content}
                  </ReactMarkdown>
                </div>
              ) : (
                <span className="whitespace-pre-wrap">{m.content}</span>
              )}
            </div>
          </div>
        ))}

        {loading && (
          <div className="flex justify-start">
            <div className="rounded-xl bg-white border border-[#dcdcdc] px-4 py-3 text-[15px] font-medium text-[#0e0e0e]">
              {t('chat_thinking')}{'.'.repeat(dots)}
            </div>
          </div>
        )}

        <div ref={endRef} />
      </div>

      <div ref={chatBarRef} className="fixed left-0 right-0 bottom-0 z-50 bg-white border-t border-[#eeeeee]">
        <div className="max-w-5xl mx-auto px-4 py-4">
          <div className="border-2 border-[#9F1D23] bg-white shadow-sm focus-within:ring-2 focus-within:ring-[#9F1D23] focus-within:ring-offset-2">
            <div className="flex items-stretch gap-2">
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault()
                    void ask()
                  }
                }}
                placeholder={t('chat_placeholder')}
                rows={1}
                disabled={loading}
                className={[
                  'flex-1 resize-none outline-none',
                  'bg-[#f5f5f5]',
                  'px-4 py-3',
                  'text-[15px] font-bold text-[#0e0e0e]',
                  'placeholder:text-[#9F1D23] placeholder:opacity-60 placeholder:font-normal',
                  'leading-[24px]',
                ].join(' ')}
              />
              <button
                onClick={() => void ask()}
                disabled={loading || !input.trim()}
                className={[
                  'w-[92px]',
                  'bg-[#9F1D23] text-white',
                  'text-[15px] font-semibold',
                  'cursor-pointer',
                  'disabled:cursor-not-allowed',
                ].join(' ')}
              >
                {t('chat_send')}
              </button>
            </div>
          </div>

          {error && <p className="mt-2 text-center text-xs text-red-600">{error}</p>}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'
import { useAuthUser, useSupabase } from '@/app/providers'

type ProfileRow = { points: number }

export default function PointsHeader() {
  // ?????꾨줈?앺듃??媛앹껜 ?뺥깭濡??대젮??r
  const { user } = useAuthUser()
  const supabase = useSupabase()

  const [points, setPoints] = useState<number>(0)
  const [loadingPoints, setLoadingPoints] = useState(false)

  // ??Google 怨꾩젙 ?대쫫 (user_metadata?먯꽌)
  const googleName = useMemo(() => {
    const meta = (user?.user_metadata as any) ?? null
    return meta?.full_name || meta?.name || meta?.email || null
  }, [user])

  useEffect(() => {
    let alive = true

    async function run() {
      if (!user) {
        setPoints(0)
        return
      }

      setLoadingPoints(true)
      const { data, error } = await supabase
        .from('profiles')
        .select('points')
        .eq('id', user.id)
        .maybeSingle<ProfileRow>()

      if (!alive) return

      if (error) {
        setPoints(0)
      } else {
        setPoints(data?.points ?? 0)
      }
      setLoadingPoints(false)
    }

    run()
    return () => {
      alive = false
    }
  }, [user, supabase])

  async function signInWithGoogle() {
    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo: `${location.origin}/auth/callback` },
    })
  }

  return (
    <div className="flex items-center justify-between gap-3">
      <div className="text-sm">
        <span className="font-semibold">Points:</span>{' '}
        <span>{loadingPoints ? '...' : points}</span>
        {user && googleName ? (
          <span className="ml-2 text-neutral-600">({googleName})</span>
        ) : null}
      </div>

      {!user ? (
        <button
          onClick={signInWithGoogle}
          className="rounded-md bg-black px-3 py-2 text-sm text-white"
        >
          Sign in with Google
        </button>
      ) : null}
    </div>
  )
}

