'use client'

import { useState } from 'react'
import { useAuthUser, useSupabase } from '@/app/providers'

const MSG_NO_QUESTION = 'Please ask at least one question in the AI Parenting Coach and then claim.'
const MSG_NEED_SIGNIN = 'Please sign in to claim today?셲 reward.'
const MSG_ALREADY = 'You already claimed today?셲 reward.'

type ClaimResponse =
  | { ok: true; points_added: number; cycle_pos: number; streak_total: number }
  | { ok: false; reason: string; error?: string }

function stripTrailingSlash(s: string) {
  return s.replace(/\/$/, '')
}

function getSiteOrigin() {
  const envSite = (process.env.NEXT_PUBLIC_SITE_URL || '').trim()
  if (envSite) return stripTrailingSlash(envSite)
  if (typeof window !== 'undefined') return window.location.origin
  return ''
}

export default function ClaimTodayButton() {
  const { user, loading: authLoading } = useAuthUser()
  const supabase = useSupabase()
  const [loading, setLoading] = useState(false)

  async function signInWithGoogle() {
    const base = getSiteOrigin() || location.origin
    // ??濡쒓렇????reward濡??뚯븘?ㅺ쾶 next 吏??r
    const redirectTo = `${base}/auth/callback?next=/reward`

    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo },
    })
  }

  async function handleClaim() {
    // ??auth 濡쒕뵫 以묒씠硫??대┃ 諛⑹?
    if (authLoading) return

    if (!user) {
      const go = confirm(`${MSG_NEED_SIGNIN}\n\nSign in with Google now?`)
      if (go) await signInWithGoogle()
      return
    }

    setLoading(true)
    try {
      const res = await fetch('/api/rewards/claim', { method: 'POST' })

      let json: ClaimResponse | null = null
      try {
        json = (await res.json()) as ClaimResponse
      } catch {
        json = null
      }

      // ??HTTP ?먯껜媛 ?ㅽ뙣(500 ??硫??쒕쾭媛 以 ?먮윭瑜?理쒕???蹂댁뿬二쇨린
      if (!res.ok) {
        const msg =
          (json as any)?.error ||
          (json as any)?.reason ||
          `HTTP ${res.status}`
        alert(`Something went wrong. Please try again.\n\n${msg}`)
        return
      }

      if (!json || json.ok !== true) {
        const reason = (json as any)?.reason

        if (reason === 'no_question_today') {
          alert(MSG_NO_QUESTION)
          return
        }
        if (reason === 'already_claimed') {
          alert(MSG_ALREADY)
          return
        }
        if (reason === 'not_authenticated') {
          alert(MSG_NEED_SIGNIN)
          return
        }

        // ??reason/error媛 ?덉쑝硫?洹몃?濡?異쒕젰 (?붾쾭源낆뿉 以묒슂)
        const extra = (json as any)?.error ? `\n\n${(json as any).error}` : ''
        alert(`Something went wrong. Please try again.${extra}`)
        return
      }

      alert(`Reward claimed! +${json.points_added} points`)
      location.reload()
    } finally {
      setLoading(false)
    }
  }

  const disabled = loading || authLoading

  return (
    <button
      onClick={handleClaim}
      disabled={disabled}
      className="rounded-md bg-red-600 px-4 py-2 text-white disabled:opacity-60"
    >
      {authLoading ? 'Loading...' : loading ? 'Claiming...' : 'Claim today'}
    </button>
  )
}

import { cookies } from 'next/headers'

export type Locale = 'en' | 'ko' | 'th' | 'ms' | 'id'

export const defaultLocale: Locale = 'en'
export const locales: Locale[] = ['en', 'ko', 'th', 'ms', 'id']

export const COOKIE_NAME = 'NEXT_LOCALE'

function getDictionaryLoader(locale: Locale) {
  switch (locale) {
    case 'ko':
      // @ts-ignore
      return () => import('./messages/ko/index')
    case 'th':
      // @ts-ignore
      return () => import('./messages/th/index')
    case 'ms':
      // @ts-ignore
      return () => import('./messages/ms/index')
    case 'id':
      // @ts-ignore
      return () => import('./messages/id/index')
    case 'en':
    default:
      // @ts-ignore
      return () => import('./messages/en/index')
  }
}

export async function getLocale(): Promise<Locale> {
  const cookieStore = await cookies()
  const localeCookie = cookieStore.get(COOKIE_NAME)?.value

  if (localeCookie && locales.includes(localeCookie as Locale)) {
    return localeCookie as Locale
  }

  return defaultLocale
}

export async function getDictionary(namespace: 'navbar' | 'about' | 'coach' | 'news' | 'team' | 'common' | 'kyk'): Promise<any> {
  const locale = await getLocale()

  try {
    const loader = getDictionaryLoader(locale)
    const dict = await loader()
    return dict[namespace]
  } catch (error) {
    console.error(`Failed to load dictionary for locale ${locale} and namespace ${namespace}`, error)
    const fallbackLoader = getDictionaryLoader(defaultLocale)
    const fallbackDict = await fallbackLoader()
    return fallbackDict[namespace]
  }
}

import { cookies } from 'next/headers'
import { createServerClient } from '@supabase/ssr'
import type { Database } from '@/lib/database.types'

export type AdminAuthResult =
  | { ok: true; user: any }
  | { ok: false; status: 401; error: string; detail: string }
  | { ok: false; status: 403; error: string; detail: string }

export async function requireAdminAuth(): Promise<AdminAuthResult> {
  const cookieStore = await cookies()

  const supabase = createServerClient<Database>(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options))
          } catch {}
        },
      },
    }
  )

  // 1. Verify Authentication
  const { data: authData, error: authError } = await supabase.auth.getUser()
  if (authError || !authData?.user) {
    return {
      ok: false,
      status: 401,
      error: 'not_authenticated',
      detail: authError?.message || 'No user session found.',
    }
  }

  const user = authData.user

  // 2. Check ADMIN_EMAILS environment variable
  const rawAdminEmails = process.env.ADMIN_EMAILS || ''
  const adminEmails = rawAdminEmails
    .split(',')
    .map((s) => s.trim().toLowerCase())
    .filter(Boolean)

  if (user.email && adminEmails.includes(user.email.toLowerCase())) {
    return { ok: true, user }
  }

  // 3. Fallback to Database Query: profiles.is_admin
  const { data: profile, error: profileErr } = await supabase
    .from('profiles')
    .select('is_admin')
    .eq('id', user.id)
    .maybeSingle()

  if (profileErr) {
    console.error('[requireAdminAuth] Error fetching profile:', profileErr)
  }

  if (profile?.is_admin === true) {
    return { ok: true, user }
  }

  // 4. Deny Access (403 Forbidden)
  return {
    ok: false,
    status: 403,
    error: 'forbidden_admin_required',
    detail: 'Administrative privileges are required to access this resource.',
  }
}

/**
 * Normalizes locales safely to one of the 5 base keys.
 * e.g., 'en-US' -> 'en', 'ko-KR' -> 'ko', 'ms-MY' -> 'ms'
 */
export function normalizeLocale(locale?: string | null): string {
  if (!locale) return 'en'
  const lower = locale.toLowerCase()
  if (lower.startsWith('ko')) return 'ko' // Korean
  if (lower.startsWith('id')) return 'id' // Indonesian
  if (lower.startsWith('ms')) return 'ms' // Malay 
  if (lower.startsWith('th')) return 'th' // Thai
  return 'en' // English fallback
}

/**
 * Resolves standard _i18n JSONB data.
 * Chain of fallback: JSONB[locale] -> JSONB['en'] -> baseString
 * Note: existing base string should always map to EN according to data sync rules.
 */
export function resolveI18n(baseString: string | null | undefined, i18nJsonb: any, inputLocale: string): string {
  const safeBase = baseString || ''
  const locale = normalizeLocale(inputLocale)

  if (i18nJsonb && typeof i18nJsonb === 'object') {
    // 1. Target Locale
    const val = i18nJsonb[locale]
    if (val && typeof val === 'string' && val.trim() !== '') {
      return val
    }
    // 2. English Fallback in JSONB
    const enVal = i18nJsonb['en']
    if (enVal && typeof enVal === 'string' && enVal.trim() !== '') {
      return enVal
    }
  }

  // 3. Absolute Base String Fallback
  return safeBase
}

